"use client";

import React, { useEffect, useCallback } from "react";
import Link from "next/link";
import {
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
  SheetDescription,
} from "@/components/ui/sheet";
import { Button } from "@/components/ui/button";
import {
  getOrderDetail,
  API_BASE_URL,
  type OrderDetail,
  type InvoiceSummary,
} from "@/lib/api";
import {
  Package,
  Truck,
  CheckCircle,
  Download,
  Headphones,
  QrCode,
  ExternalLink,
  FileText,
  Loader2,
  ArrowRight,
} from "lucide-react";

const CARRIER_URLS: Record<string, (tn: string) => string> = {
  yurtici: (tn) =>
    `https://www.yurticikargo.com/tr/online-servisler/gonderi-sorgula?code=${tn}`,
  aras: (tn) =>
    `https://www.araskargo.com.tr/taki.aspx?p_kargo_takip_no=${tn}`,
  mng: (tn) =>
    `https://www.mngkargo.com.tr/gonderi-takip/?gonderino=${tn}`,
  ptt: (tn) =>
    `https://gonderitakip.ptt.gov.tr/Track/Verify?q=${tn}`,
};

const STATUS_ORDER = [
  "DRAFT", "TEXT_APPROVED", "COVER_APPROVED", "PAYMENT_PENDING", "PAID",
  "PROCESSING", "READY_FOR_PRINT", "SHIPPED", "DELIVERED",
];

function formatDate(iso: string): string {
  return new Date(iso).toLocaleDateString("tr-TR", {
    day: "numeric",
    month: "long",
    year: "numeric",
  });
}

async function downloadInvoice(orderId: string, invoiceNumber: string): Promise<void> {
  const token = typeof window !== "undefined" ? localStorage.getItem("token") : null;
  const res = await fetch(`${API_BASE_URL}/orders/${orderId}/invoice/download`, {
    headers: token ? { Authorization: `Bearer ${token}` } : {},
  });
  if (!res.ok) throw new Error("─░ndirme ba┼şar─▒s─▒z");
  const blob = await res.blob();
  const href = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = href;
  a.download = `fatura_${invoiceNumber}.pdf`;
  a.click();
  URL.revokeObjectURL(href);
}

function InvoiceBlock({
  orderId,
  invoice,
  formatDate,
}: {
  orderId: string;
  invoice: InvoiceSummary;
  formatDate: (iso: string) => string;
}) {
  const [downloading, setDownloading] = React.useState(false);
  const handleDownload = async () => {
    setDownloading(true);
    try {
      await downloadInvoice(orderId, invoice.invoice_number);
    } finally {
      setDownloading(false);
    }
  };
  return (
    <div className="rounded-xl border bg-white p-4">
      <h3 className="mb-2 flex items-center gap-2 text-sm font-semibold text-slate-700">
        <FileText className="h-4 w-4" />
        Fatura
      </h3>
      <p className="text-xs text-slate-600">
        {invoice.invoice_number}
        {invoice.issued_at && ` ┬À ${formatDate(invoice.issued_at)}`}
      </p>
      {invoice.pdf_ready && (
        <Button
          size="sm"
          variant="outline"
          className="mt-2 text-xs"
          onClick={handleDownload}
          disabled={downloading}
        >
          {downloading ? (
            <Loader2 className="mr-1 h-3 w-3 animate-spin" />
          ) : (
            <Download className="mr-1 h-3 w-3" />
          )}
          {downloading ? "─░ndiriliyor..." : "PDF ─░ndir"}
        </Button>
      )}
    </div>
  );
}

interface AccountOrderDetailSheetProps {
  orderId: string | null;
  open: boolean;
  onOpenChange: (open: boolean) => void;
}

export function AccountOrderDetailSheet({
  orderId,
  open,
  onOpenChange,
}: AccountOrderDetailSheetProps) {
  const [order, setOrder] = React.useState<OrderDetail | null>(null);
  const [error, setError] = React.useState<string | null>(null);
  const [loading, setLoading] = React.useState(false);

  const loadDetail = useCallback(async () => {
    if (!orderId) return;
    setLoading(true);
    setError(null);
    try {
      const data = await getOrderDetail(orderId, "pages,timeline");
      setOrder(data);
    } catch {
      setOrder(null);
      setError("Sipari┼ş detaylar─▒ y├╝klenemedi.");
    } finally {
      setLoading(false);
    }
  }, [orderId]);

  useEffect(() => {
    if (open && orderId) loadDetail();
    else if (!open) { setOrder(null); setError(null); }
  }, [open, orderId, loadDetail]);

  if (!orderId) return null;

  const currentIdx = order ? STATUS_ORDER.indexOf(order.status) : -1;
  const isTerminal = order?.status === "CANCELLED" || order?.status === "REFUNDED";

  return (
    <Sheet open={open} onOpenChange={onOpenChange}>
      <SheetContent side="right" className="w-full overflow-y-auto sm:max-w-2xl p-0">
        {loading && !order ? (
          <div className="flex h-full items-center justify-center">
            <SheetTitle className="sr-only">Y├╝kleniyor</SheetTitle>
            <div className="flex items-center gap-3">
              <Loader2 className="h-5 w-5 animate-spin text-slate-400" />
              <span className="text-sm text-slate-500">Y├╝kleniyor...</span>
            </div>
          </div>
        ) : error ? (
          <div className="flex h-full flex-col items-center justify-center gap-3 px-6 text-center">
            <SheetTitle className="sr-only">Hata</SheetTitle>
            <p className="text-sm text-slate-600">{error}</p>
            <Button size="sm" variant="outline" onClick={loadDetail}>
              Tekrar Dene
            </Button>
          </div>
        ) : order ? (
          <div className="flex h-full flex-col">
            <SheetHeader className="border-b px-6 py-4">
              <div className="flex items-start justify-between gap-3">
                <div className="min-w-0 flex-1">
                  <SheetTitle className="truncate text-lg text-slate-800">
                    {order.child_name}
                  </SheetTitle>
                  <SheetDescription className="mt-0.5 text-slate-500">
                    Sipari┼ş #{order.id.slice(0, 8).toUpperCase()}
                    {" ┬À "}
                    {formatDate(order.created_at)}
                    {order.payment_amount != null && order.payment_amount > 0 && (
                      <span className="ml-2 font-medium text-slate-700">
                        {order.payment_amount.toFixed(2)} TL
                      </span>
                    )}
                  </SheetDescription>
                </div>
              </div>

              {/* Status banner */}
              {!isTerminal && (
                <div className="mt-3 rounded-xl border border-purple-100 bg-purple-50/50 p-3">
                  <p className="text-sm font-semibold text-purple-900">
                    {order.status_description}
                  </p>
                  {order.status_hint && (
                    <p className="mt-0.5 text-xs text-purple-700">
                      {order.status_hint}
                    </p>
                  )}
                </div>
              )}
            </SheetHeader>

            <div className="flex-1 overflow-y-auto px-6 py-4 space-y-4">
              {/* Timeline stepper */}
              {!isTerminal && currentIdx >= STATUS_ORDER.indexOf("PAID") && (
                <div className="rounded-xl border bg-white p-4">
                  <h3 className="mb-3 text-sm font-semibold text-slate-700">Sipari┼ş Durumu</h3>
                  <div className="flex items-center justify-between">
                    {["├ûdendi", "├£retiliyor", "Bask─▒ya Haz─▒r", "Kargoda", "Teslim Edildi"].map((label, i) => {
                      const stepIdx = STATUS_ORDER.indexOf(["PAID", "PROCESSING", "READY_FOR_PRINT", "SHIPPED", "DELIVERED"][i]);
                      const done = currentIdx >= stepIdx;
                      const active = order.status === (["PAID", "PROCESSING", "READY_FOR_PRINT", "SHIPPED", "DELIVERED"][i]);
                      return (
                        <div key={label} className="flex flex-1 flex-col items-center">
                          <div
                            className={`flex h-8 w-8 shrink-0 items-center justify-center rounded-full text-xs font-bold ${done ? "bg-purple-600 text-white" : "bg-slate-200 text-slate-400"
                              } ${active ? "ring-2 ring-purple-200" : ""}`}
                          >
                            {done ? <CheckCircle className="h-4 w-4" /> : i + 1}
                          </div>
                          <span className={`mt-1.5 text-center text-[10px] ${done ? "text-purple-600" : "text-slate-400"}`}>
                            {label}
                          </span>
                        </div>
                      );
                    })}
                  </div>
                </div>
              )}

              {/* Page images preview */}
              {order.pages && order.pages.length > 0 && (
                <div className="rounded-xl border bg-white p-4">
                  <h3 className="mb-3 text-sm font-semibold text-slate-700">Kitap ├ûnizleme</h3>
                  <div className="flex gap-2 overflow-x-auto pb-2">
                    {order.pages.map((p) => {
                      const url = p.image_url || p.preview_image_url;
                      if (!url) return null;
                      return (
                        <div key={p.page_number} className="flex shrink-0 flex-col items-center">
                          <img
                            src={url}
                            alt={`Sayfa ${p.page_number}`}
                            className="h-20 w-auto rounded-lg border object-cover"
                          />
                          <span className="mt-1 text-[10px] text-slate-500">
                            {p.is_cover ? "Kapak" : p.page_number}
                          </span>
                        </div>
                      );
                    })}
                  </div>
                </div>
              )}

              {/* Production progress */}
              {order.status === "PROCESSING" && (
                <div className="rounded-xl border bg-white p-4">
                  <h3 className="mb-2 flex items-center gap-2 text-sm font-semibold text-slate-700">
                    <Loader2 className="h-4 w-4" />
                    ├£retim ─░lerlemesi
                  </h3>
                  <div className="flex justify-between text-xs text-slate-600">
                    <span>{order.completed_pages} / {order.total_pages} sayfa</span>
                    <span className="font-semibold text-purple-600">
                      {order.total_pages > 0 ? Math.round((order.completed_pages / order.total_pages) * 100) : 0}%
                    </span>
                  </div>
                  <div className="mt-2 h-2 w-full overflow-hidden rounded-full bg-slate-100">
                    <div
                      className="h-full rounded-full bg-purple-500 transition-all"
                      style={{
                        width: `${order.total_pages > 0 ? (order.completed_pages / order.total_pages) * 100 : 0}%`,
                      }}
                    />
                  </div>
                </div>
              )}

              {/* Cargo tracking */}
              {order.tracking_number && (
                <div className="rounded-xl border bg-white p-4">
                  <h3 className="mb-2 flex items-center gap-2 text-sm font-semibold text-slate-700">
                    <Truck className="h-4 w-4" />
                    Kargo Takibi
                  </h3>
                  <div className="flex items-center justify-between gap-3">
                    <div>
                      <p className="text-sm font-medium text-slate-800">{order.carrier || "Kargo"}</p>
                      <p className="text-xs text-slate-500">{order.tracking_number}</p>
                    </div>
                    {order.carrier && CARRIER_URLS[(order.carrier || "").toLowerCase()] && (
                      <a
                        href={CARRIER_URLS[(order.carrier || "").toLowerCase()]!(order.tracking_number!)}
                        target="_blank"
                        rel="noopener noreferrer"
                      >
                        <Button size="sm" variant="outline" className="text-xs">
                          Takip Et
                          <ExternalLink className="ml-1 h-3 w-3" />
                        </Button>
                      </a>
                    )}
                  </div>
                </div>
              )}

              {/* Digital downloads */}
              {(order.final_pdf_url || order.audio_file_url || order.qr_code_url) && (
                <div className="rounded-xl border bg-white p-4">
                  <h3 className="mb-3 flex items-center gap-2 text-sm font-semibold text-slate-700">
                    <Download className="h-4 w-4" />
                    Dijital ─░├ğerikler
                  </h3>
                  <div className="grid gap-2 sm:grid-cols-3">
                    {order.final_pdf_url && (
                      <a
                        href={order.final_pdf_url}
                        target="_blank"
                        rel="noopener noreferrer"
                        className="flex items-center gap-2 rounded-lg border p-3 text-sm font-medium text-slate-700 hover:bg-slate-50"
                      >
                        <Download className="h-4 w-4 text-green-600" />
                        PDF ─░ndir
                      </a>
                    )}
                    {order.audio_file_url && (
                      <a
                        href={order.audio_file_url}
                        target="_blank"
                        rel="noopener noreferrer"
                        className="flex items-center gap-2 rounded-lg border p-3 text-sm font-medium text-slate-700 hover:bg-slate-50"
                      >
                        <Headphones className="h-4 w-4 text-blue-600" />
                        Sesli Kitap
                      </a>
                    )}
                    {order.qr_code_url && (
                      <a
                        href={order.qr_code_url}
                        target="_blank"
                        rel="noopener noreferrer"
                        className="flex items-center gap-2 rounded-lg border p-3 text-sm font-medium text-slate-700 hover:bg-slate-50"
                      >
                        <QrCode className="h-4 w-4 text-purple-600" />
                        QR Kod
                      </a>
                    )}
                  </div>
                </div>
              )}

              {/* Invoice */}
              {order.invoice && (
                <InvoiceBlock orderId={order.id} invoice={order.invoice} formatDate={formatDate} />
              )}

              {/* Shipping address */}
              {order.shipping_address && (
                <div className="rounded-xl border bg-white p-4">
                  <h3 className="mb-2 flex items-center gap-2 text-sm font-semibold text-slate-700">
                    <Truck className="h-4 w-4" />
                    Teslimat Adresi
                  </h3>
                  <p className="text-sm text-slate-600">
                    {order.shipping_address.full_name}
                    <br />
                    {order.shipping_address.address_line1}
                    {order.shipping_address.address_line2 && (
                      <><br />{order.shipping_address.address_line2}</>
                    )}
                    <br />
                    {order.shipping_address.district && `${order.shipping_address.district}, `}
                    {order.shipping_address.city}
                    {order.shipping_address.postal_code && ` ${order.shipping_address.postal_code}`}
                  </p>
                </div>
              )}

              {/* Link to full detail page */}
              <Link href={`/account/orders/${order.id}`}>
                <Button variant="outline" className="w-full rounded-xl">
                  Tam Detay G├Âr├╝nt├╝le
                  <ArrowRight className="ml-2 h-4 w-4" />
                </Button>
              </Link>
            </div>
          </div>
        ) : null}
      </SheetContent>
    </Sheet>
  );
}

"use client";

import { useEffect, useState, useCallback, useRef } from "react";
import { useParams, useRouter } from "next/navigation";
import Link from "next/link";
import {
  getOrderDetail,
  deletePhotoNow,
  getUserProfile,
  API_BASE_URL,
  type OrderDetail,
  type InvoiceSummary,
} from "@/lib/api";
import { Button } from "@/components/ui/button";
import { useToast } from "@/hooks/use-toast";
import {
  ArrowLeft,
  Package,
  Truck,
  CheckCircle,
  Clock,
  Download,
  Headphones,
  QrCode,
  ExternalLink,
  MessageCircle,
  Mail,
  AlertCircle,
  Loader2,
  Shield,
  Trash2,
  RefreshCw,
  FileText,
  XCircle,
} from "lucide-react";

// ÔöÇÔöÇÔöÇ Constants ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

const TIMELINE_STEPS = [
  { key: "PAID", label: "├ûdendi", icon: CheckCircle },
  { key: "PROCESSING", label: "├£retiliyor", icon: Loader2 },
  { key: "READY_FOR_PRINT", label: "Bask─▒ya Haz─▒r", icon: Package },
  { key: "SHIPPED", label: "Kargoda", icon: Truck },
  { key: "DELIVERED", label: "Teslim Edildi", icon: CheckCircle },
] as const;

const STATUS_ORDER = [
  "DRAFT",
  "TEXT_APPROVED",
  "COVER_APPROVED",
  "PAYMENT_PENDING",
  "PAID",
  "PROCESSING",
  "READY_FOR_PRINT",
  "SHIPPED",
  "DELIVERED",
];

const CARRIER_URLS: Record<string, (tn: string) => string> = {
  yurtici: (tn) =>
    `https://www.yurticikargo.com/tr/online-servisler/gonderi-sorgula?code=${tn}`,
  aras: (tn) =>
    `https://www.araskargo.com.tr/taki.aspx?p_kargo_takip_no=${tn}`,
  mng: (tn) =>
    `https://www.mngkargo.com.tr/gonderi-takip/?gonderino=${tn}`,
  ptt: (tn) =>
    `https://gonderitakip.ptt.gov.tr/Track/Verify?q=${tn}`,
};

const PROCESSING_POLL_INTERVAL = 10_000;

// ÔöÇÔöÇÔöÇ Helpers ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

async function downloadBlob(url: string, filename: string): Promise<void> {
  const token = localStorage.getItem("token");
  const res = await fetch(url, {
    headers: token ? { Authorization: `Bearer ${token}` } : {},
  });
  if (!res.ok) throw new Error("─░ndirme ba┼şar─▒s─▒z");
  const blob = await res.blob();
  const href = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = href;
  a.download = filename;
  a.click();
  URL.revokeObjectURL(href);
}

function formatDate(iso: string): string {
  return new Date(iso).toLocaleDateString("tr-TR", {
    day: "numeric",
    month: "long",
    year: "numeric",
  });
}

// ÔöÇÔöÇÔöÇ Sub-components ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

function Skeleton({ className = "" }: { className?: string }) {
  return <div className={`animate-pulse rounded bg-gray-200 ${className}`} />;
}

function Card({
  children,
  className = "",
}: {
  children: React.ReactNode;
  className?: string;
}) {
  return (
    <div className={`rounded-2xl border bg-white p-4 sm:p-5 ${className}`}>
      {children}
    </div>
  );
}

function CardTitle({
  icon: Icon,
  children,
}: {
  icon: React.ElementType;
  children: React.ReactNode;
}) {
  return (
    <div className="mb-3 flex items-center gap-2">
      <Icon className="h-4 w-4 text-gray-500" />
      <h3 className="text-sm font-semibold text-gray-700">{children}</h3>
    </div>
  );
}

// ÔöÇÔöÇÔöÇ Timeline Stepper ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

function TimelineStepper({ status }: { status: string }) {
  const currentIdx = STATUS_ORDER.indexOf(status);

  if (status === "CANCELLED" || status === "REFUNDED") {
    return (
      <Card className="border-red-100 bg-red-50/50">
        <div className="flex items-center gap-3">
          <div className="flex h-10 w-10 shrink-0 items-center justify-center rounded-full bg-red-100">
            <XCircle className="h-5 w-5 text-red-600" />
          </div>
          <div>
            <p className="text-sm font-semibold text-red-800">
              {status === "CANCELLED" ? "─░ptal Edildi" : "─░ade Edildi"}
            </p>
            <p className="text-xs text-red-600">
              {status === "CANCELLED"
                ? "Bu sipari┼ş iptal edilmi┼ştir."
                : "Bu sipari┼ş i├ğin iade i┼şlemi tamamlanm─▒┼şt─▒r."}
            </p>
          </div>
        </div>
      </Card>
    );
  }

  if (currentIdx < STATUS_ORDER.indexOf("PAID")) return null;

  return (
    <Card>
      <h3 className="mb-4 text-sm font-semibold text-gray-700">
        Sipari┼ş Durumu
      </h3>
      <div className="flex items-center justify-between">
        {TIMELINE_STEPS.map((step, i) => {
          const stepIdx = STATUS_ORDER.indexOf(step.key);
          const done = currentIdx >= stepIdx;
          const active = status === step.key;
          return (
            <div key={step.key} className="flex flex-1 flex-col items-center">
              <div className="relative flex w-full items-center">
                {i > 0 && (
                  <div
                    className={`h-0.5 flex-1 transition-colors ${
                      done ? "bg-purple-500" : "bg-gray-200"
                    }`}
                  />
                )}
                <div
                  className={`relative z-10 flex h-8 w-8 shrink-0 items-center justify-center rounded-full text-xs font-bold transition-all ${
                    done
                      ? active
                        ? "bg-purple-600 text-white ring-4 ring-purple-100"
                        : "bg-purple-500 text-white"
                      : "bg-gray-200 text-gray-400"
                  }`}
                >
                  {done ? (
                    <CheckCircle className="h-4 w-4" />
                  ) : (
                    <span>{i + 1}</span>
                  )}
                </div>
                {i < TIMELINE_STEPS.length - 1 && (
                  <div
                    className={`h-0.5 flex-1 transition-colors ${
                      currentIdx > stepIdx ? "bg-purple-500" : "bg-gray-200"
                    }`}
                  />
                )}
              </div>
              <span
                className={`mt-2 text-center text-[10px] leading-tight sm:text-xs ${
                  active
                    ? "font-semibold text-purple-700"
                    : done
                      ? "text-purple-600"
                      : "text-gray-400"
                }`}
              >
                {step.label}
              </span>
            </div>
          );
        })}
      </div>
    </Card>
  );
}

// ÔöÇÔöÇÔöÇ Production Progress ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

function ProductionProgress({
  order,
  onLoadPages,
}: {
  order: OrderDetail;
  onLoadPages: () => void;
}) {
  if (order.status !== "PROCESSING") return null;

  const progress =
    order.total_pages > 0
      ? Math.round((order.completed_pages / order.total_pages) * 100)
      : 0;

  return (
    <Card>
      <CardTitle icon={Loader2}>├£retim ─░lerlemesi</CardTitle>
      <div className="flex items-center justify-between text-sm text-gray-600">
        <span>
          {order.completed_pages} / {order.total_pages} sayfa tamamland─▒
        </span>
        <span className="font-semibold text-purple-600">{progress}%</span>
      </div>
      <div className="mt-2 h-2.5 w-full overflow-hidden rounded-full bg-gray-100">
        <div
          className="h-full rounded-full bg-gradient-to-r from-purple-500 to-violet-500 transition-all duration-700 ease-out"
          style={{ width: `${progress}%` }}
        />
      </div>

      {order.pages && order.pages.length > 0 ? (
        <div className="mt-4 grid grid-cols-8 gap-1.5 sm:grid-cols-12 md:grid-cols-16">
          {order.pages.map((p) => (
            <div
              key={p.page_number}
              title={`Sayfa ${p.page_number}: ${p.status}`}
              className={`flex h-7 w-7 items-center justify-center rounded-lg text-[10px] font-medium transition-colors ${
                p.status === "FULL_GENERATED"
                  ? "bg-green-100 text-green-700"
                  : p.status === "PREVIEW_GENERATED"
                    ? "bg-blue-100 text-blue-700"
                    : p.status === "FAILED"
                      ? "bg-red-100 text-red-700"
                      : "bg-gray-100 text-gray-400"
              }`}
            >
              {p.page_number}
            </div>
          ))}
        </div>
      ) : (
        <button
          onClick={onLoadPages}
          className="mt-3 text-xs font-medium text-purple-600 hover:text-purple-800"
        >
          Sayfa detaylar─▒n─▒ g├Âster
        </button>
      )}
    </Card>
  );
}

// ÔöÇÔöÇÔöÇ Cargo Tracking ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

function CargoTracking({ order }: { order: OrderDetail }) {
  if (!order.tracking_number) return null;

  const carrierKey = (order.carrier || "").toLowerCase();
  const trackingUrl =
    CARRIER_URLS[carrierKey]?.(order.tracking_number) ?? null;

  return (
    <Card>
