// ÔöÇÔöÇÔöÇ Main Page ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

export default function OrderDetailPage() {
  const { id } = useParams<{ id: string }>();
  const router = useRouter();
  const { toast } = useToast();

  const [order, setOrder] = useState<OrderDetail | null>(null);
  const [loading, setLoading] = useState(true);
  const [deletingPhoto, setDeletingPhoto] = useState(false);
  const [pagesLoaded, setPagesLoaded] = useState(false);
  const [timelineLoaded, setTimelineLoaded] = useState(false);
  const [isGuest, setIsGuest] = useState(false);
  const pollRef = useRef<ReturnType<typeof setInterval> | null>(null);

  // Initial load
  useEffect(() => {
    if (!id) return;
    Promise.all([
      getOrderDetail(id),
      getUserProfile().catch(() => null),
    ])
      .then(([orderData, profile]) => {
        setOrder(orderData);
        if (profile) setIsGuest(profile.is_guest === true);
      })
      .catch(() =>
        toast({
          title: "Hata",
          description: "Sipari┼ş y├╝klenemedi",
          variant: "destructive",
        }),
      )
      .finally(() => setLoading(false));
  }, [id, toast]);

  // Auto-poll during PROCESSING
  useEffect(() => {
    if (order?.status !== "PROCESSING" || !id) return;

    pollRef.current = setInterval(async () => {
      try {
        const updated = await getOrderDetail(id, "pages");
        setOrder((prev) => {
          if (!prev) return prev;
          return {
            ...prev,
            status: updated.status,
            status_description: updated.status_description,
            status_hint: updated.status_hint,
            completed_pages: updated.completed_pages,
            total_pages: updated.total_pages,
            pages: updated.pages ?? prev.pages,
            invoice: updated.invoice ?? prev.invoice,
          };
        });
        setPagesLoaded(true);
        if (updated.status !== "PROCESSING" && pollRef.current) {
          clearInterval(pollRef.current);
          pollRef.current = null;
        }
      } catch {
        /* silent ÔÇö retry next interval */
      }
    }, PROCESSING_POLL_INTERVAL);

    return () => {
      if (pollRef.current) {
        clearInterval(pollRef.current);
        pollRef.current = null;
      }
    };
  }, [order?.status, id]);

  const loadPages = useCallback(async () => {
    if (!id || pagesLoaded) return;
    try {
      const detail = await getOrderDetail(id, "pages");
      setOrder((prev) =>
        prev ? { ...prev, pages: detail.pages } : prev,
      );
      setPagesLoaded(true);
    } catch {
      /* silent */
    }
  }, [id, pagesLoaded]);

  const loadTimeline = useCallback(async () => {
    if (!id || timelineLoaded) return;
    try {
      const detail = await getOrderDetail(id, "timeline");
      setOrder((prev) =>
        prev
          ? { ...prev, timeline_events: detail.timeline_events }
          : prev,
      );
      setTimelineLoaded(true);
    } catch {
      /* silent */
    }
  }, [id, timelineLoaded]);

  const refreshOrder = useCallback(async () => {
    if (!id) return;
    try {
      const updated = await getOrderDetail(id);
      setOrder(updated);
    } catch {
      /* silent */
    }
  }, [id]);

  const handleDeletePhoto = async () => {
    if (
      !confirm(
        "Foto─şraf ve y├╝z verileri kal─▒c─▒ olarak silinecek. Devam etmek istiyor musunuz?",
      )
    )
      return;
    setDeletingPhoto(true);
    try {
      await deletePhotoNow(order!.id);
      toast({
        title: "Silindi",
        description: "Foto─şraf ve y├╝z verileri silindi.",
      });
      const updated = await getOrderDetail(order!.id);
      setOrder(updated);
    } catch (e) {
      toast({
        title: "Hata",
        description: e instanceof Error ? e.message : "Silinemedi",
        variant: "destructive",
      });
    } finally {
      setDeletingPhoto(false);
    }
  };

  // ÔöÇÔöÇÔöÇ Loading skeleton ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  if (loading) {
    return (
      <div className="space-y-4 py-6">
        <Skeleton className="h-4 w-16" />
        <div className="flex items-start justify-between">
          <div className="space-y-2">
            <Skeleton className="h-6 w-40" />
            <Skeleton className="h-4 w-56" />
          </div>
          <Skeleton className="h-6 w-20" />
        </div>
        <Skeleton className="h-24 rounded-2xl" />
        <Skeleton className="h-20 rounded-2xl" />
        <Skeleton className="h-16 rounded-2xl" />
        <Skeleton className="h-16 rounded-2xl" />
      </div>
    );
  }

  if (!order) {
    return (
      <div className="flex flex-col items-center py-20">
        <Package className="h-12 w-12 text-gray-300" />
        <p className="mt-4 text-gray-600">Sipari┼ş bulunamad─▒</p>
        <Link href="/account">
          <Button variant="outline" className="mt-4 rounded-xl">
            Sipari┼şlerime D├Ân
          </Button>
        </Link>
      </div>
    );
  }

  const isGuestOrder = order.is_guest_order || isGuest;

  return (
    <div className="space-y-4 pb-24 sm:pb-6">
      {/* Back button */}
      <button
        onClick={() => router.back()}
        className="inline-flex items-center gap-1.5 rounded-lg px-2 py-1.5 text-sm text-gray-500 transition-colors hover:bg-gray-100 hover:text-gray-700 active:bg-gray-200 min-h-[36px]"
        aria-label="Geri d├Ân"
      >
        <ArrowLeft className="h-4 w-4" />
        Geri
      </button>

      {/* Header */}
      <div className="flex items-start justify-between gap-4">
        <div className="min-w-0">
          <h1 className="text-xl font-bold text-gray-900 sm:text-2xl">
            {order.child_name}
          </h1>
          <p className="mt-0.5 text-sm text-gray-500">
            Sipari┼ş: {order.id.slice(0, 8)}... &middot;{" "}
            {formatDate(order.created_at)}
          </p>
        </div>
        {order.payment_amount != null && order.payment_amount > 0 && (
          <span className="shrink-0 text-lg font-bold text-gray-900">
            {order.payment_amount.toFixed(2)} TL
          </span>
        )}
      </div>

      {/* Status banner */}
      {order.status !== "CANCELLED" && order.status !== "REFUNDED" && (
        <div className="rounded-2xl border-2 border-purple-100 bg-gradient-to-r from-purple-50 to-violet-50 p-4">
          <div className="flex items-start gap-3">
            <div className="flex h-10 w-10 shrink-0 items-center justify-center rounded-full bg-purple-100">
              <AlertCircle className="h-5 w-5 text-purple-600" />
            </div>
            <div>
              <p className="text-sm font-semibold text-purple-900">
                ┼Şu An Ne Oluyor?
              </p>
              <p className="text-sm text-purple-700">
                {order.status_description}
              </p>
              {order.status_hint && (
                <p className="mt-0.5 text-xs text-purple-600/70">
                  {order.status_hint}
                </p>
              )}
            </div>
          </div>
        </div>
      )}

      {/* Timeline stepper */}
      <TimelineStepper status={order.status} />

      {/* Production progress (auto-polls) */}
      <ProductionProgress order={order} onLoadPages={loadPages} />

      {/* Cargo tracking */}
      <CargoTracking order={order} />

      {/* Digital downloads */}
      <DigitalDownloads order={order} />

      {/* Invoice card */}
      <InvoiceCard
        invoice={order.invoice}
        orderId={order.id}
        isGuestOrder={isGuestOrder}
        onRefresh={refreshOrder}
      />

      {/* Billing info */}
      <BillingInfo order={order} />

      {/* Shipping address */}
      <ShippingAddress order={order} />

      {/* KVKK */}
      <KvkkCard
        order={order}
        onDelete={handleDeletePhoto}
        deleting={deletingPhoto}
      />

      {/* Support */}
      <SupportCard orderId={order.id} />

      {/* Timeline events */}
      <TimelineEvents
        order={order}
        loaded={timelineLoaded}
        onLoad={loadTimeline}
      />

      {/* Delivered date */}
      {order.delivered_at && (
        <p className="text-center text-xs text-gray-400">
          Teslim tarihi: {formatDate(order.delivered_at)}
        </p>
      )}
    </div>
  );
}

"use client";

import { useEffect, useState, useCallback, useRef } from "react";
import Link from "next/link";
import { useRouter } from "next/navigation";
import {
  getUserOrdersPaginated,
  getUserTrials,
  getUserPaidTrials,
  type PaginatedOrders,
  type UserTrial,
} from "@/lib/api";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import GuestConvertBanner from "@/components/GuestConvertBanner";
import { AccountOrderDetailSheet } from "./_components/AccountOrderDetailSheet";
import { AccountTrialDetailSheet } from "./_components/AccountTrialDetailSheet";
import {
  Package,
  Search,
  Truck,
  Headphones,
  Loader2,
  ChevronRight,
} from "lucide-react";

const STATUS_CONFIG: Record<string, { label: string; color: string; bg: string }> = {
  DRAFT: { label: "Taslak", color: "text-gray-600", bg: "bg-gray-100" },
  TEXT_APPROVED: { label: "Metin Onayland─▒", color: "text-blue-600", bg: "bg-blue-50" },
  COVER_APPROVED: { label: "Kapak Onayland─▒", color: "text-blue-600", bg: "bg-blue-50" },
  PAYMENT_PENDING: { label: "├ûdeme Bekliyor", color: "text-amber-600", bg: "bg-amber-50" },
  PAID: { label: "├ûdendi", color: "text-green-600", bg: "bg-green-50" },
  PROCESSING: { label: "├£retiliyor", color: "text-purple-600", bg: "bg-purple-50" },
  COMPLETING: { label: "Kitap Haz─▒rlan─▒yor", color: "text-purple-600", bg: "bg-purple-50" },
  COMPLETED: { label: "Tamamland─▒", color: "text-emerald-600", bg: "bg-emerald-50" },
  READY_FOR_PRINT: { label: "Bask─▒ya Haz─▒r", color: "text-indigo-600", bg: "bg-indigo-50" },
  SHIPPED: { label: "Kargoda", color: "text-orange-600", bg: "bg-orange-50" },
  DELIVERED: { label: "Teslim Edildi", color: "text-emerald-600", bg: "bg-emerald-50" },
  CANCELLED: { label: "─░ptal", color: "text-red-600", bg: "bg-red-50" },
  REFUNDED: { label: "─░ade", color: "text-red-600", bg: "bg-red-50" },
};

const FILTERS = [
  { key: "", label: "T├╝m├╝" },
  { key: "active", label: "Devam Ediyor" },
  { key: "delivered", label: "Teslim Edilen" },
  { key: "cancelled", label: "─░ptal / ─░ade" },
];

function matchesSearch(
  q: string,
  childName: string,
  storyTitle?: string | null,
  orderId?: string,
): boolean {
  const s = (q || "").trim().toLowerCase();
  if (!s) return true;
  const child = (childName || "").toLowerCase();
  const story = (storyTitle || "").toLowerCase();
  const id = (orderId || "").toLowerCase();
  return child.includes(s) || story.includes(s) || id.includes(s);
}

export default function AccountPage() {
  const router = useRouter();
  const [data, setData] = useState<PaginatedOrders | null>(null);
  const [trials, setTrials] = useState<UserTrial[]>([]);
  const [paidTrials, setPaidTrials] = useState<UserTrial[]>([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState("");
  const [search, setSearch] = useState("");
  const [debouncedSearch, setDebouncedSearch] = useState("");
  const [page, setPage] = useState(1);
  const [isGuest, setIsGuest] = useState(false);
  const [selectedOrderId, setSelectedOrderId] = useState<string | null>(null);
  const [selectedTrial, setSelectedTrial] = useState<UserTrial | null>(null);
  const debounceRef = useRef<ReturnType<typeof setTimeout>>();
  const abortRef = useRef<AbortController | null>(null);

  useEffect(() => {
    debounceRef.current = setTimeout(() => {
      setDebouncedSearch(search);
      setPage(1);
    }, 400);
    return () => clearTimeout(debounceRef.current);
  }, [search]);

  const fetchOrders = useCallback(async () => {
    abortRef.current?.abort();
    const controller = new AbortController();
    abortRef.current = controller;
    setLoading(true);
    try {
      const res = await getUserOrdersPaginated({
        status_filter: filter || undefined,
        search: debouncedSearch || undefined,
        page,
        per_page: 10,
      });
      if (!controller.signal.aborted) setData(res);
    } catch {
      if (!abortRef.current?.signal.aborted) setData(null);
    } finally {
      if (!abortRef.current?.signal.aborted) setLoading(false);
    }
  }, [filter, debouncedSearch, page]);

  useEffect(() => {
    fetchOrders();
    try {
      const user = JSON.parse(localStorage.getItem("user") || "{}");
      setIsGuest(user.is_guest === true);
    } catch {
      /* ignore */
    }
  }, [fetchOrders]);

  // Fetch trials only once on mount ÔÇö not on every filter/search change
  useEffect(() => {
    getUserTrials().then(setTrials).catch(() => {});
    getUserPaidTrials().then(setPaidTrials).catch(() => {});
  }, []);

  const orders = data?.items ?? [];
  const totalPages = data?.total_pages ?? 0;
  const totalCount = data?.total ?? 0;

  const isOngoingTrial = (t: UserTrial) =>
    ["COMPLETING", "COMPLETED", "PAYMENT_PENDING"].includes(t.status);
  const visibleTrials =
    filter === "" || filter === "active" ? trials : [];
  const visiblePaidTrials =
    filter === ""
      ? paidTrials
      : filter === "active"
        ? paidTrials.filter(isOngoingTrial)
        : filter === "delivered" || filter === "cancelled"
          ? []
          : paidTrials;
  const visibleOrders = orders;
  const searchMatches = (child: string, story?: string | null, id?: string) =>
    matchesSearch(debouncedSearch, child, story, id);
  const filteredTrials = visibleTrials.filter((t) =>
    searchMatches(t.child_name, t.story_title),
  );
  const filteredPaidTrials = visiblePaidTrials.filter((t) =>
    searchMatches(t.child_name, t.story_title),
  );
  const filteredOrders = visibleOrders;
  // totalCount from paginated API + all local trials for accurate total
  const combinedCount = totalCount + trials.length + paidTrials.length;

  const handleSelectOrder = (id: string) => {
    setSelectedTrial(null);
    setSelectedOrderId(id);
  };

  const handleSelectTrial = (trial: UserTrial) => {
    setSelectedOrderId(null);
    setSelectedTrial(trial);
  };

  return (
    <div>
      {isGuest && (
        <GuestConvertBanner onConverted={() => { setIsGuest(false); fetchOrders(); }} />
      )}

      <div className="mb-4 flex items-center justify-between">
        <h1 className="text-xl font-bold text-slate-800">
          Sipari┼şlerim
          {combinedCount > 0 && (
            <span className="ml-2 text-sm font-normal text-slate-500">({combinedCount})</span>
          )}
        </h1>
      </div>

        {/* Toolbar - filters + search */}
        <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
          <div className="flex gap-2 overflow-x-auto">
            {FILTERS.map((f) => (
              <button
                key={f.key}
                onClick={() => { setFilter(f.key); setPage(1); }}
                className={`whitespace-nowrap rounded-full px-4 py-1.5 text-xs font-medium transition-colors ${
                  filter === f.key
                    ? "bg-purple-600 text-white"
                    : "border bg-white text-gray-600 hover:bg-gray-50"
                }`}
              >
                {f.label}
              </button>
            ))}
          </div>
          <div className="relative flex-1 sm:max-w-xs">
            <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-gray-400" />
            <Input
              placeholder="├çocuk ad─▒ veya sipari┼ş no ile ara..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="h-9 rounded-lg pl-9 text-sm"
            />
          </div>
        </div>

        <div className="overflow-hidden rounded-lg border bg-white">
          {loading ? (
            <div className="flex items-center justify-center py-16">
              <div className="flex items-center gap-3">
                <Loader2 className="h-5 w-5 animate-spin text-purple-500" />
                <span className="text-sm text-slate-500">Sipari┼şler y├╝kleniyor...</span>
              </div>
            </div>
          ) : filteredTrials.length === 0 && filteredPaidTrials.length === 0 && filteredOrders.length === 0 ? (
            <div className="flex flex-col items-center justify-center py-16">
              <Package className="h-12 w-12 text-slate-300" />
