                </thead>
                <tbody>
                  {/* Devam eden ├Ânizlemeler */}
                  {filteredTrials.map((t) => {
                    const cfg = STATUS_CONFIG[t.status] || STATUS_CONFIG.PROCESSING;
                    return (
                      <tr
                        key={`trial-${t.id}`}
