                  {/* ├ûdenen ├Ânizlemeler / Hikaye kitaplar─▒ */}
                  {filteredPaidTrials.map((t) => {
                    const cfg = STATUS_CONFIG[t.status] || STATUS_CONFIG.PROCESSING;
                    return (
                      <tr
                        key={`trial-${t.id}`}
