                    );
                  })}
                  {/* Orders from Order table */}
                  {orders.map((order) => {
                    const cfg = STATUS_CONFIG[order.status] || STATUS_CONFIG.DRAFT;
                    const progress = order.total_pages > 0
                      ? Math.round((order.completed_pages / order.total_pages) * 100)
                      : 0;
                    return (
                      <tr
