            <p
              className="text-xs italic leading-relaxed"
              style={{ color: config.text_color, fontSize: "8px", lineHeight: "1.5" }}
            >
              {config.dedication_text}
            </p>
          </div>
        )}

        {/* ORTA: Ebeveyn ├ûnerileri ÔÇö sayfan─▒n kalbi */}
        <div className="flex-1">
          <div
            className="text-xs font-bold mb-1.5 text-center tracking-wider uppercase"
            style={{ color: config.primary_color, fontSize: "8px", letterSpacing: "0.12em" }}
          >
            {config.tips_title}
          </div>
          <div className="space-y-0.5">
            {config.tips_content.split("\n").filter(Boolean).map((line, i) => (
              <p
                key={i}
                className="leading-snug"
                style={{
                  color: config.text_color,
                  fontSize: `${Math.min(config.tips_font_size, 8)}px`,
                  lineHeight: "1.45",
                }}
              >
                {line}
              </p>
            ))}
          </div>
        </div>

        {/* AYRA├ç */}
        {config.show_decorative_lines && (
          <div className="flex items-center gap-1.5 my-2">
            <div className="h-px flex-1" style={{ background: config.border_color }} />
            <div className="flex gap-0.5">
              {[...Array(3)].map((_, i) => (
                <div
                  key={i}
                  className="w-0.5 h-0.5 rounded-full"
                  style={{ background: config.accent_color, opacity: 0.7 }}
                />
              ))}
            </div>
            <div className="h-px flex-1" style={{ background: config.border_color }} />
          </div>
        )}

        {/* ALT: QR + ─░leti┼şim */}
        <div className="flex items-end justify-between gap-2">
          {/* ─░leti┼şim Bilgileri */}
          <div className="flex-1">
            <p
              className="font-semibold"
              style={{ color: config.primary_color, fontSize: "7px", letterSpacing: "0.04em" }}
            >
              {config.company_website}
            </p>
            <p style={{ color: config.text_color, fontSize: "6.5px", opacity: 0.7 }}>
              {config.company_email}
            </p>
            {config.company_phone && (
              <p style={{ color: config.text_color, fontSize: "6.5px", opacity: 0.7 }}>
                {config.company_phone}
              </p>
            )}
            <p className="mt-1.5" style={{ color: config.text_color, fontSize: "6px", opacity: 0.5 }}>
              {config.copyright_text}
            </p>
          </div>

          {/* QR Kodu */}
          {config.qr_enabled && (
            <div className="text-center shrink-0">
              <div
                className="flex items-center justify-center rounded"
                style={{
                  width: "44px",
                  height: "44px",
                  background: "white",
                  border: `1px solid ${config.border_color}`,
                  padding: "3px",
                }}
              >
                {/* QR grid sim├╝lasyonu */}
                <div className="grid grid-cols-5 gap-px w-full h-full">
                  {[...Array(25)].map((_, i) => (
                    <div
                      key={i}
                      className="rounded-sm"
                      style={{
                        background: [0,1,2,5,6,7,10,12,14,17,18,19,22,23,24].includes(i)
                          ? "#111"
                          : "transparent",
                      }}
                    />
                  ))}
                </div>
              </div>
              <p
                className="mt-0.5 text-center leading-tight"
                style={{ color: config.primary_color, fontSize: "6px" }}
              >
                {config.qr_label}
              </p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

// Renk se├ğici sat─▒r bile┼şeni
function ColorRow({
  label,
  value,
  onChange,
}: {
  label: string;
  value: string;
  onChange: (v: string) => void;
}) {
  return (
    <div>
      <Label className="mb-1 block text-xs text-gray-600">{label}</Label>
      <div className="flex items-center gap-2">
        <input
          type="color"
          value={value}
          onChange={(e) => onChange(e.target.value)}
          className="h-9 w-9 cursor-pointer rounded border border-gray-200 p-0.5"
        />
        <Input
          value={value}
          onChange={(e) => onChange(e.target.value)}
          className="h-9 font-mono text-sm uppercase"
        />
      </div>
    </div>
  );
}

export default function BackCoverAdminPage() {
  const [configs, setConfigs] = useState<BackCoverConfig[]>([]);
  const [selectedConfig, setSelectedConfig] = useState<BackCoverConfig | null>(null);
  const [formData, setFormData] = useState<Omit<BackCoverConfig, "id">>(defaultConfig);
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);
  const { toast } = useToast();

  const upd = <K extends keyof Omit<BackCoverConfig, "id">>(
    key: K,
    value: Omit<BackCoverConfig, "id">[K]
  ) => setFormData((prev) => ({ ...prev, [key]: value }));

  useEffect(() => {
    const token = localStorage.getItem("token");
    if (!token) { window.location.href = "/auth/login"; return; }
    fetchConfigs();
  }, []);

  const fetchConfigs = async () => {
    setLoading(true);
    try {
      const token = localStorage.getItem("token");
      const res = await fetch(`${API_BASE_URL}/admin/back-cover?include_inactive=true`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      if (res.ok) {
        const data = await res.json();
        setConfigs(data);
        if (data.length > 0) {
          setSelectedConfig(data[0]);
          setFormData(data[0]);
        } else {
          await createDefaultConfig(token);
        }
      } else if (res.status === 401) {
        window.location.href = "/auth/login";
      }
    } catch {
      toast({ title: "Hata", description: "Yap─▒land─▒rmalar y├╝klenemedi", variant: "destructive" });
    } finally {
      setLoading(false);
    }
  };

  const createDefaultConfig = async (token: string | null) => {
    try {
      const res = await fetch(`${API_BASE_URL}/admin/back-cover`, {
        method: "POST",
        headers: { "Content-Type": "application/json", Authorization: `Bearer ${token}` },
        body: JSON.stringify(defaultConfig),
      });
      if (res.ok) {
        const newCfg = await res.json();
        setConfigs([newCfg]);
        setSelectedConfig(newCfg);
        setFormData(newCfg);
        toast({ title: "Ba┼şar─▒l─▒", description: "Varsay─▒lan yap─▒land─▒rma olu┼şturuldu" });
      }
    } catch { /* ignore */ }
  };

  const handleSave = async () => {
    setSaving(true);
    try {
      const token = localStorage.getItem("token");
      const url = selectedConfig
        ? `${API_BASE_URL}/admin/back-cover/${selectedConfig.id}`
        : `${API_BASE_URL}/admin/back-cover`;
      const res = await fetch(url, {
        method: selectedConfig ? "PATCH" : "POST",
        headers: { "Content-Type": "application/json", Authorization: `Bearer ${token}` },
        body: JSON.stringify(formData),
      });
      if (res.ok) {
        toast({ title: "Kaydedildi", description: "─░├ğ kapak arkas─▒ yap─▒land─▒rmas─▒ g├╝ncellendi." });
        fetchConfigs();
      } else {
        toast({ title: "Hata", description: "Kaydetme ba┼şar─▒s─▒z", variant: "destructive" });
      }
    } catch {
      toast({ title: "Hata", description: "Ba─şlant─▒ hatas─▒", variant: "destructive" });
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 p-6">
      <div className="mx-auto max-w-7xl">

        {/* Header */}
        <div className="mb-6 flex items-center justify-between">
          <div className="flex items-center gap-4">
            <Link href="/admin">
              <Button variant="ghost" size="icon">
                <ArrowLeft className="h-5 w-5" />
              </Button>
            </Link>
            <div>
              <h1 className="text-2xl font-bold">─░├ğ Kapak Arkas─▒ Y├Ânetimi</h1>
              <p className="text-gray-500 text-sm">
                Kitab─▒n ilk sayfas─▒n─▒n arkas─▒ ÔÇö marka kimli─şi, ebeveyn rehberi ve QR kodu
              </p>
            </div>
          </div>
          <div className="flex gap-2">
            <Button
              variant="outline"
              onClick={() => {
                setSelectedConfig(null);
                setFormData({ ...defaultConfig, name: `Yap─▒land─▒rma ${configs.length + 1}`, is_default: false });
              }}
            >
              <Plus className="mr-2 h-4 w-4" />
              Yeni
            </Button>
            <Button onClick={handleSave} disabled={saving} className="bg-purple-700 hover:bg-purple-800">
              <Save className="mr-2 h-4 w-4" />
              {saving ? "Kaydediliyor..." : "Kaydet"}
            </Button>
          </div>
        </div>

        <div className="grid grid-cols-1 gap-6 xl:grid-cols-4">

          {/* Sol: Yap─▒land─▒rma listesi */}
          <div className="xl:col-span-1">
            <Card>
              <CardHeader className="pb-3">
                <CardTitle className="text-sm font-semibold text-gray-700">Yap─▒land─▒rmalar</CardTitle>
              </CardHeader>
              <CardContent className="space-y-2 pt-0">
                {loading && <p className="text-xs text-gray-400">Y├╝kleniyorÔÇĞ</p>}
                {!loading && configs.length === 0 && (
                  <p className="text-xs text-gray-400">Hen├╝z yap─▒land─▒rma yok.</p>
                )}
                {configs.map((cfg) => (
                  <button
                    key={cfg.id}
                    onClick={() => { setSelectedConfig(cfg); setFormData(cfg); }}
                    className={`w-full rounded-lg border p-3 text-left text-sm transition ${
                      selectedConfig?.id === cfg.id
                        ? "border-purple-500 bg-purple-50 font-medium"
                        : "border-gray-200 hover:border-purple-300"
                    }`}
                  >
                    <div className="font-medium">{cfg.name}</div>
                    <div className="flex gap-2 mt-0.5">
                      {cfg.is_default && (
                        <span className="text-xs text-purple-600 font-medium">Varsay─▒lan</span>
                      )}
                      {!cfg.is_active && (
                        <span className="text-xs text-red-400">Pasif</span>
                      )}
                    </div>
                  </button>
                ))}
              </CardContent>
            </Card>

            {/* Canl─▒ ├Ânizleme */}
            <Card className="mt-4">
              <CardHeader className="pb-2">
                <CardTitle className="text-sm font-semibold text-gray-700 flex items-center gap-2">
                  <Eye className="h-4 w-4" />
                  Canl─▒ ├ûnizleme
                </CardTitle>
                <CardDescription className="text-xs">Ger├ğek sayfa oranlar─▒nda (A5)</CardDescription>
              </CardHeader>
              <CardContent className="flex justify-center pt-0 pb-4">
                <BackCoverPreview config={formData} />
              </CardContent>
            </Card>
          </div>

          {/* Sa─ş: D├╝zenleme formu */}
          <div className="space-y-5 xl:col-span-3">

            {/* Temel ayarlar */}
            <Card>
              <CardHeader className="pb-3">
                <CardTitle className="text-base flex items-center gap-2">
                  <BookOpen className="h-4 w-4 text-purple-600" />
                  Temel Bilgiler
                </CardTitle>
              </CardHeader>
              <CardContent className="space-y-4">
                <div className="grid grid-cols-3 gap-4">
                  <div>
                    <Label>Yap─▒land─▒rma Ad─▒</Label>
                    <Input value={formData.name} onChange={(e) => upd("name", e.target.value)} />
                  </div>
                  <div className="flex items-center gap-6 pt-6">
                    <label className="flex items-center gap-2 cursor-pointer">
                      <Switch
                        checked={formData.is_default}
                        onCheckedChange={(v) => upd("is_default", v)}
                      />
                      <span className="text-sm">Varsay─▒lan</span>
                    </label>
                    <label className="flex items-center gap-2 cursor-pointer">
                      <Switch
                        checked={formData.is_active}
                        onCheckedChange={(v) => upd("is_active", v)}
                      />
                      <span className="text-sm">Aktif</span>
                    </label>
                  </div>
                </div>
              </CardContent>
            </Card>

            {/* Marka & Firma */}
            <Card>
              <CardHeader className="pb-3">
                <CardTitle className="text-base flex items-center gap-2">
                  <Building2 className="h-4 w-4 text-purple-600" />
                  Marka & Firma Bilgileri
                </CardTitle>
                <CardDescription className="text-xs">Sayfa ├╝st├╝nde g├Âr├╝n├╝r ÔÇö okuyucunun g├Âz├╝ne ├ğarpan ilk bilgi</CardDescription>
              </CardHeader>
              <CardContent className="space-y-4">
                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <Label>Firma / Marka Ad─▒</Label>
                    <Input value={formData.company_name} onChange={(e) => upd("company_name", e.target.value)} />
                  </div>
                  <div>
                    <Label>Slogan <span className="text-gray-400 text-xs">(kapak alt─▒ italik metin)</span></Label>
                    <Input value={formData.tagline} onChange={(e) => upd("tagline", e.target.value)} />
                  </div>
                </div>
                <div className="grid grid-cols-3 gap-4">
                  <div>
                    <Label>Website</Label>
                    <Input value={formData.company_website} onChange={(e) => upd("company_website", e.target.value)} />
                  </div>
                  <div>
                    <Label>E-posta</Label>
                    <Input value={formData.company_email} onChange={(e) => upd("company_email", e.target.value)} />
                  </div>
                  <div>
                    <Label>Telefon <span className="text-gray-400 text-xs">(iste─şe ba─şl─▒)</span></Label>
                    <Input
                      value={formData.company_phone || ""}
                      onChange={(e) => upd("company_phone", e.target.value || null)}
                      placeholder="+90 ÔÇĞ"
                    />
                  </div>
                </div>
                <div>
                  <Label>─░thaf / Ki┼şisel Mesaj <span className="text-gray-400 text-xs">(italik kutu ÔÇö bo┼ş b─▒rak─▒labilir)</span></Label>
                  <Textarea
                    value={formData.dedication_text}
                    onChange={(e) => upd("dedication_text", e.target.value)}
                    rows={2}
                    placeholder="Bu kitap, senin i├ğinÔÇĞ"
                  />
                </div>
                <div>
                  <Label>Telif Hakk─▒ Metni</Label>
                  <Input value={formData.copyright_text} onChange={(e) => upd("copyright_text", e.target.value)} />
                </div>
              </CardContent>
            </Card>

            {/* Ebeveyn ├ûnerileri */}
            <Card>
              <CardHeader className="pb-3">
                <CardTitle className="text-base flex items-center gap-2">
                  <Star className="h-4 w-4 text-purple-600" />
                  Ebeveyn ├ûnerileri <span className="text-xs font-normal text-gray-400">(Okuma Rehberi)</span>
                </CardTitle>
                <CardDescription className="text-xs">
                  Sayfan─▒n en geni┼ş alan─▒ ÔÇö ebeveyne ├ğocukla kitap okuma k─▒lavuzu
                </CardDescription>
              </CardHeader>
              <CardContent className="space-y-4">
                <div>
                  <Label>B├Âl├╝m Ba┼şl─▒─ş─▒</Label>
                  <Input value={formData.tips_title} onChange={(e) => upd("tips_title", e.target.value)} />
                </div>
                <div>
                  <Label>├ûneriler <span className="text-gray-400 text-xs">(her sat─▒r ayr─▒ ├Âneri ÔÇö ÔÇó ile ba┼şlay─▒n)</span></Label>
