                    />
                  </div>
                </div>
              </CardContent>
            </Card>

            {/* QR Kodu */}
            <Card>
              <CardHeader className="pb-3">
                <CardTitle className="text-base flex items-center gap-2">
                  <QrCode className="h-4 w-4 text-purple-600" />
                  QR Kodu ÔÇö Sesli Kitap
                </CardTitle>
                <CardDescription className="text-xs">
                  Alt sa─şda konumlan─▒r; sesli kitab─▒ dinlemek i├ğin telefonla okutulur
                </CardDescription>
              </CardHeader>
              <CardContent className="space-y-4">
                <label className="flex items-center gap-3 cursor-pointer">
                  <Switch checked={formData.qr_enabled} onCheckedChange={(v) => upd("qr_enabled", v)} />
                  <span className="text-sm font-medium">QR Kodu G├Âster</span>
                </label>
                {formData.qr_enabled && (
                  <div className="grid grid-cols-3 gap-4">
                    <div>
                      <Label>Boyut (mm)</Label>
                      <Input
                        type="number"
                        min={20}
                        max={50}
                        value={formData.qr_size_mm}
                        onChange={(e) => upd("qr_size_mm", parseFloat(e.target.value) || 32)}
                      />
                    </div>
                    <div>
                      <Label>Konum</Label>
                      <select
                        value={formData.qr_position}
                        onChange={(e) => upd("qr_position", e.target.value)}
                        className="h-10 w-full rounded-md border border-input bg-background px-3 text-sm"
                      >
                        <option value="bottom_right">Sa─ş Alt (├Ânerilen)</option>
                        <option value="bottom_left">Sol Alt</option>
                        <option value="center">Orta</option>
                      </select>
                    </div>
                    <div>
                      <Label>Etiket</Label>
                      <Input
                        value={formData.qr_label}
                        onChange={(e) => upd("qr_label", e.target.value)}
                        placeholder="Sesli Kitab─▒ Dinle"
                      />
                    </div>
                  </div>
                )}
              </CardContent>
            </Card>

            {/* Renkler & G├Ârsel Stil */}
            <Card>
              <CardHeader className="pb-3">
                <CardTitle className="text-base flex items-center gap-2">
                  <Palette className="h-4 w-4 text-purple-600" />
                  Renkler & G├Ârsel Stil
                </CardTitle>
                <CardDescription className="text-xs">
                  Arka plan gradient, tipografi ve dekoratif ├Â─şe renkleri
                </CardDescription>
              </CardHeader>
              <CardContent className="space-y-5">
                <div className="grid grid-cols-2 gap-4 md:grid-cols-3">
                  <ColorRow
                    label="Arka Plan Ba┼şlang─▒├ğ"
                    value={formData.background_color}
                    onChange={(v) => upd("background_color", v)}
                  />
                  <ColorRow
                    label="Arka Plan Biti┼ş (gradient)"
                    value={formData.background_gradient_end}
                    onChange={(v) => upd("background_gradient_end", v)}
                  />
                  <ColorRow
                    label="Ana Renk (ba┼şl─▒k, QR etiketi)"
                    value={formData.primary_color}
                    onChange={(v) => upd("primary_color", v)}
                  />
                  <ColorRow
                    label="Vurgu Rengi (y─▒ld─▒z, ayra├ğ)"
                    value={formData.accent_color}
                    onChange={(v) => upd("accent_color", v)}
                  />
                  <ColorRow
                    label="Metin Rengi"
                    value={formData.text_color}
                    onChange={(v) => upd("text_color", v)}
                  />
                  <ColorRow
                    label="├çer├ğeve Rengi"
                    value={formData.border_color}
                    onChange={(v) => upd("border_color", v)}
                  />
                </div>

                <div className="flex flex-wrap gap-6 pt-2">
                  <label className="flex items-center gap-2 cursor-pointer">
                    <Switch checked={formData.show_border} onCheckedChange={(v) => upd("show_border", v)} />
                    <span className="text-sm">├çer├ğeve G├Âster</span>
                  </label>
                  <label className="flex items-center gap-2 cursor-pointer">
                    <Switch checked={formData.show_stars} onCheckedChange={(v) => upd("show_stars", v)} />
                    <span className="text-sm">Y─▒ld─▒zlar G├Âster</span>
                  </label>
                  <label className="flex items-center gap-2 cursor-pointer">
                    <Switch
                      checked={formData.show_decorative_lines}
                      onCheckedChange={(v) => upd("show_decorative_lines", v)}
                    />
                    <span className="text-sm">Dekoratif ├çizgi & Ayra├ğlar</span>
                  </label>
                </div>
              </CardContent>
            </Card>

          </div>
        </div>
      </div>
    </div>
  );
}

