"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import Link from "next/link";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import { useToast } from "@/hooks/use-toast";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { API_BASE_URL } from "@/lib/api";
import { getAdminHeaders as getAuthHeaders } from "@/lib/adminFetch";

// Types
interface KVKKStats {
  total_users: number;
  total_orders_with_photos: number;
  pending_deletions: number;
  deleted_last_30_days: number;
  next_scheduled_deletion: string | null;
  kvkk_retention_days: number;
}

interface DeletionQueueItem {
  order_id: string;
  child_name: string;
  delivered_at: string;
  scheduled_deletion: string;
  days_remaining: number;
  has_photo: boolean;
  has_cloned_voice: boolean;
}

interface AuditLogItem {
  id: number;
  action: string;
  order_id: string | null;
  user_id: string | null;
  details: Record<string, unknown> | null;
  created_at: string;
}

interface UserListItem {
  id: string;
  email: string | null;
  full_name: string | null;
  orders_count: number;
  photos_count: number;
  created_at: string;
  is_active: boolean;
}

export default function KVKKPage() {
  const [stats, setStats] = useState<KVKKStats | null>(null);
  const [deletionQueue, setDeletionQueue] = useState<DeletionQueueItem[]>([]);
  const [auditLogs, setAuditLogs] = useState<AuditLogItem[]>([]);
  const [users, setUsers] = useState<UserListItem[]>([]);
  const [userSearch, setUserSearch] = useState("");
  const [loading, setLoading] = useState(true);
  const [cleanupLoading, setCleanupLoading] = useState(false);
  const [deleteLoading, setDeleteLoading] = useState<string | null>(null);
  const router = useRouter();
  const { toast } = useToast();

  useEffect(() => {
    checkAuth();
    loadAllData();
  }, []);

  const checkAuth = () => {
    const user = localStorage.getItem("user");
    if (!user) {
      router.push("/auth/login");
      return;
    }
    const userData = JSON.parse(user);
    if (userData.role !== "admin") {
      toast({
        title: "Yetkisiz Eri┼şim",
        description: "Bu sayfaya eri┼şim yetkiniz yok",
        variant: "destructive",
      });
      router.push("/");
    }
  };


  const loadAllData = async () => {
    setLoading(true);
    try {
      await Promise.all([loadStats(), loadDeletionQueue(), loadAuditLogs(), loadUsers()]);
    } catch (error) {
      console.error("Failed to load KVKK data:", error);
    } finally {
      setLoading(false);
    }
  };

  const loadStats = async () => {
    try {
      const response = await fetch(`${API_BASE_URL}/admin/kvkk/stats`, { headers: getAuthHeaders() });
      if (response.ok) {
        setStats(await response.json());
      }
    } catch (error) {
      console.error("Failed to load stats:", error);
    }
  };

  const loadDeletionQueue = async () => {
    try {
      const response = await fetch(`${API_BASE_URL}/admin/kvkk/deletion-queue`, { headers: getAuthHeaders() });
      if (response.ok) {
        setDeletionQueue(await response.json());
      }
    } catch (error) {
      console.error("Failed to load deletion queue:", error);
    }
  };

  const loadAuditLogs = async () => {
    try {
      const response = await fetch(`${API_BASE_URL}/admin/kvkk/audit-logs`, { headers: getAuthHeaders() });
      if (response.ok) {
        setAuditLogs(await response.json());
      }
    } catch (error) {
      console.error("Failed to load audit logs:", error);
    }
  };

  const loadUsers = async (search?: string) => {
    try {
      const url = search
        ? `${API_BASE_URL}/admin/kvkk/users?search=${encodeURIComponent(search)}`
        : `${API_BASE_URL}/admin/kvkk/users`;
      const response = await fetch(url, { headers: getAuthHeaders() });
      if (response.ok) {
        setUsers(await response.json());
      }
    } catch (error) {
      console.error("Failed to load users:", error);
    }
  };

  const handleManualCleanup = async () => {
    if (!confirm("KVKK temizlik i┼şlemini ba┼şlatmak istedi─şinize emin misiniz?")) {
      return;
    }

    setCleanupLoading(true);
    try {
      const response = await fetch(`${API_BASE_URL}/admin/kvkk/manual-cleanup`, {
        method: "POST",
        headers: getAuthHeaders(),
      });

      if (response.ok) {
        const result = await response.json();
        toast({
          title: "Temizlik Tamamland─▒",
          description: `${result.processed} sipari┼ş i┼şlendi, ${result.deleted} dosya silindi.`,
        });
        loadAllData();
      } else {
        throw new Error("Cleanup failed");
      }
    } catch (error) {
      toast({
        title: "Hata",
        description: "Temizlik i┼şlemi ba┼şar─▒s─▒z oldu.",
        variant: "destructive",
      });
    } finally {
      setCleanupLoading(false);
    }
  };

  const handleDeleteUser = async (userId: string, email: string | null) => {
    if (
      !confirm(
        `"${email || userId}" kullan─▒c─▒s─▒n─▒n T├£M verilerini kal─▒c─▒ olarak silmek istedi─şinize emin misiniz?\n\nBu i┼şlem geri al─▒namaz!`
      )
    ) {
      return;
    }

    setDeleteLoading(userId);
    try {
      const response = await fetch(`${API_BASE_URL}/admin/kvkk/delete-user/${userId}`, {
        method: "POST",
        headers: getAuthHeaders(),
      });

      if (response.ok) {
        const result = await response.json();
        toast({
          title: "Kullan─▒c─▒ Verileri Silindi",
          description: `${result.photos_deleted} foto─şraf, ${result.audio_deleted} ses dosyas─▒ silindi. ${result.orders_anonymized} sipari┼ş anonimle┼ştirildi.`,
        });
        loadAllData();
      } else {
        throw new Error("Delete failed");
      }
    } catch (error) {
      toast({
        title: "Hata",
        description: "Silme i┼şlemi ba┼şar─▒s─▒z oldu.",
        variant: "destructive",
      });
    } finally {
      setDeleteLoading(null);
    }
  };

  const handleExportUser = async (userId: string, email: string | null) => {
    try {
      const response = await fetch(`${API_BASE_URL}/admin/kvkk/export-user-data/${userId}`, {
        headers: getAuthHeaders(),
      });

      if (response.ok) {
        const data = await response.json();
        // JSON olarak indir
        const blob = new Blob([JSON.stringify(data, null, 2)], { type: "application/json" });
        const url = window.URL.createObjectURL(blob);
        const a = document.createElement("a");
        a.href = url;
        a.download = `user-data-${email || userId}-${new Date().toISOString().split("T")[0]}.json`;
        document.body.appendChild(a);
        a.click();
        window.URL.revokeObjectURL(url);
        document.body.removeChild(a);

        toast({
          title: "Veri Export Edildi",
          description: "Kullan─▒c─▒ verileri JSON olarak indirildi.",
        });
      } else {
        throw new Error("Export failed");
      }
    } catch (error) {
      toast({
        title: "Hata",
        description: "Export i┼şlemi ba┼şar─▒s─▒z oldu.",
        variant: "destructive",
      });
    }
  };

  const handleUserSearch = () => {
    loadUsers(userSearch);
  };

  const getActionBadgeColor = (action: string) => {
    const colors: Record<string, string> = {
      KVKK_PHOTO_DELETED: "bg-red-100 text-red-800",
      USER_DATA_DELETED: "bg-red-100 text-red-800",
      USER_DATA_EXPORTED: "bg-blue-100 text-blue-800",
      MANUAL_KVKK_CLEANUP: "bg-yellow-100 text-yellow-800",
    };
    return colors[action] || "bg-gray-100 text-gray-800";
  };

  const formatDate = (dateStr: string) => {
    return new Date(dateStr).toLocaleDateString("tr-TR", {
      year: "numeric",
