  const watchedValues = form.watch();

  useEffect(() => {
    checkAuth();
    fetchOutcomes();
    fetchSyncStatus();
  }, []);

  const checkAuth = () => {
    const user = localStorage.getItem("user");
    if (!user) {
      router.push("/auth/login");
      return;
    }
    const userData = JSON.parse(user);
    if (userData.role !== "admin") {
      router.push("/");
    }
  };


  const fetchOutcomes = async () => {
    try {
      const response = await fetch(
        `${API_BASE_URL}/admin/learning-outcomes?include_inactive=true`,
        { headers: getAuthHeaders() }
      );
      if (response.status === 401) {
        router.push("/auth/login");
        return;
      }
      if (response.ok) {
        const data = await response.json();
        setOutcomes(data);
      }
    } catch (error) {
      toast({ title: "Hata", description: "Kazan─▒mlar y├╝klenemedi", variant: "destructive" });
    } finally {
      setLoading(false);
    }
  };

  const fetchSyncStatus = async () => {
    try {
      const response = await fetch(`${API_BASE_URL}/admin/learning-outcomes/sync/status`, {
        headers: getAuthHeaders(),
      });
      if (response.ok) {
        const data = await response.json();
        setSyncStatus(data);
      }
    } catch (error) {
      console.error("Failed to fetch sync status:", error);
    }
  };

  const executeSync = async () => {
    setSyncing(true);
    try {
      const response = await fetch(
        `${API_BASE_URL}/admin/learning-outcomes/sync/execute?delete_orphans=true&create_missing=true`,
        { method: "POST", headers: getAuthHeaders() }
      );
      if (response.ok) {
        const data = await response.json();
        toast({
          title: "Senkronizasyon Tamamland─▒",
          description: data.message,
        });
        fetchOutcomes();
        fetchSyncStatus();
      } else {
        const error = await response.json();
        throw new Error(error.detail || "Senkronizasyon ba┼şar─▒s─▒z");
      }
    } catch (error) {
      const message = error instanceof Error ? error.message : "Bilinmeyen hata";
      toast({ title: "Hata", description: message, variant: "destructive" });
    } finally {
      setSyncing(false);
    }
  };

  const openEditor = (outcome?: LearningOutcome) => {
    if (outcome) {
      setEditingOutcome(outcome);
      form.reset({
        name: outcome.name,
        description: outcome.description || "",
        icon_url: outcome.icon_url || "",
        color_theme: outcome.color_theme || "",
        ai_prompt_instruction: outcome.ai_prompt_instruction || "",
        ai_prompt: outcome.ai_prompt || "",
        banned_words_tr: outcome.banned_words_tr || "",
        category: outcome.category,
        category_label: outcome.category_label || "",
        age_group: outcome.age_group,
        display_order: outcome.display_order,
        is_active: outcome.is_active,
      });
    } else {
      setEditingOutcome(null);
      const nextOrder =
        outcomes.length > 0 ? Math.max(...outcomes.map((o) => o.display_order)) + 1 : 0;
      form.reset({
        name: "",
        description: "",
        icon_url: "",
        color_theme: "",
        ai_prompt_instruction: "",
        ai_prompt: "",
        banned_words_tr: "",
        category: "PersonalGrowth",
        category_label: "Ki┼şisel Geli┼şim",
        age_group: "3-10",
        display_order: nextOrder,
        is_active: true,
      });
    }
    setIsEditorOpen(true);
  };

  const closeEditor = () => {
    setIsEditorOpen(false);
    setEditingOutcome(null);
    form.reset();
  };

  const onSubmit = async (data: OutcomeFormData) => {
    try {
      const payload = {
        ...data,
        icon_url: data.icon_url || null,
        color_theme: data.color_theme || null,
        ai_prompt_instruction: data.ai_prompt_instruction || null,
        ai_prompt: data.ai_prompt || null,
        banned_words_tr: data.banned_words_tr || null,
        category_label:
          data.category_label || CATEGORIES.find((c) => c.id === data.category)?.label || null,
      };

      const url = editingOutcome
        ? `${API_BASE_URL}/admin/learning-outcomes/${editingOutcome.id}`
        : `${API_BASE_URL}/admin/learning-outcomes`;

      const response = await fetch(url, {
        method: editingOutcome ? "PATCH" : "POST",
        headers: getAuthHeaders(),
        body: JSON.stringify(payload),
      });

      if (response.ok) {
        toast({
          title: "Ba┼şar─▒l─▒",
          description: editingOutcome ? "Kazan─▒m g├╝ncellendi" : "Kazan─▒m olu┼şturuldu",
        });
        closeEditor();
        fetchOutcomes();
      } else {
        const error = await response.json();
        throw new Error(error.detail || "Hata olu┼ştu");
      }
    } catch (error) {
      const message = error instanceof Error ? error.message : "Bilinmeyen hata";
      toast({ title: "Hata", description: message, variant: "destructive" });
    }
  };

  const handleDelete = async (outcomeId: string) => {
    try {
      const response = await fetch(`${API_BASE_URL}/admin/learning-outcomes/${outcomeId}`, {
        method: "DELETE",
        headers: getAuthHeaders(),
      });

      if (response.ok) {
        toast({ title: "Ba┼şar─▒l─▒", description: "Kazan─▒m devre d─▒┼ş─▒ b─▒rak─▒ld─▒" });
        fetchOutcomes();
      }
    } catch (error) {
      toast({ title: "Hata", description: "Silme ba┼şar─▒s─▒z", variant: "destructive" });
    } finally {
      setDeleteConfirm(null);
    }
  };

  const handleDuplicate = async (outcomeId: string) => {
    try {
      const response = await fetch(
        `${API_BASE_URL}/admin/learning-outcomes/${outcomeId}/duplicate`,
        { method: "POST", headers: getAuthHeaders() }
      );

      if (response.ok) {
        toast({ title: "Ba┼şar─▒l─▒", description: "Kazan─▒m kopyaland─▒" });
        fetchOutcomes();
      }
    } catch (error) {
      toast({ title: "Hata", description: "Kopyalama ba┼şar─▒s─▒z", variant: "destructive" });
    }
  };

  const toggleActive = async (outcome: LearningOutcome) => {
    try {
      const response = await fetch(`${API_BASE_URL}/admin/learning-outcomes/${outcome.id}`, {
        method: "PATCH",
        headers: getAuthHeaders(),
        body: JSON.stringify({ is_active: !outcome.is_active }),
      });

      if (response.ok) {
        toast({ title: "Ba┼şar─▒l─▒", description: "Durum g├╝ncellendi" });
        fetchOutcomes();
      }
    } catch (error) {
      toast({ title: "Hata", description: "G├╝ncelleme ba┼şar─▒s─▒z", variant: "destructive" });
    }
  };

  // Filter outcomes
  const filteredOutcomes = outcomes.filter((o) => {
    if (activeFilter === "all") return true;
    if (activeFilter === "active") return o.is_active;
    if (activeFilter === "inactive") return !o.is_active;
    return o.category === activeFilter;
  });

  // Group by category for display
  const groupedOutcomes = filteredOutcomes.reduce(
    (acc, outcome) => {
      const cat = outcome.category;
      if (!acc[cat]) acc[cat] = [];
      acc[cat].push(outcome);
      return acc;
    },
    {} as Record<string, LearningOutcome[]>
  );

  // Preview data for form
  const previewData: Partial<LearningOutcome> = {
    name: watchedValues.name,
    description: watchedValues.description,
    icon_url: watchedValues.icon_url,
    color_theme: watchedValues.color_theme,
    category: watchedValues.category,
    category_label: watchedValues.category_label,
    ai_prompt_instruction: watchedValues.ai_prompt_instruction,
    is_active: watchedValues.is_active,
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-gray-50 to-gray-100">
      {/* Header */}
      <header className="sticky top-0 z-40 border-b bg-white shadow-sm">
        <div className="mx-auto flex max-w-[1600px] items-center justify-between px-6 py-4">
          <div className="flex items-center gap-4">
            <Button variant="ghost" size="sm" onClick={() => router.push("/admin")}>
              <ArrowLeft className="mr-1 h-4 w-4" />
              Geri
            </Button>
            <div>
              <h1 className="flex items-center gap-2 text-2xl font-bold text-gray-900">
                <Target className="h-6 w-6 text-purple-600" />
                Kazan─▒m Y├Ânetimi
              </h1>
              <p className="mt-0.5 text-sm text-gray-500">
                Hikaye e─şitim kazan─▒mlar─▒n─▒ ve AI talimatlar─▒n─▒ y├Ânetin
              </p>
            </div>
          </div>
          <Button onClick={() => openEditor()} className="bg-purple-600 hover:bg-purple-700">
            <Plus className="mr-2 h-4 w-4" />
            Yeni Kazan─▒m
          </Button>
        </div>
      </header>

      <main className="mx-auto max-w-[1600px] px-6 py-8">
        {/* Stats & Filters */}
        <div className="mb-8 flex flex-wrap items-center gap-4">
          <div className="flex items-center gap-2 text-sm">
            <span className="text-gray-500">Toplam:</span>
            <Badge variant="secondary">{outcomes.length}</Badge>
          </div>
          <div className="flex items-center gap-2 text-sm">
            <span className="text-gray-500">Aktif:</span>
            <Badge className="bg-green-100 text-green-700">
              {outcomes.filter((o) => o.is_active).length}
            </Badge>
          </div>

          <Separator orientation="vertical" className="h-6" />

          {/* Category filters */}
          <div className="flex flex-wrap gap-2">
            <Button
              variant={activeFilter === "all" ? "default" : "outline"}
              size="sm"
              onClick={() => setActiveFilter("all")}
            >
              T├╝m├╝
            </Button>
            {CATEGORIES.map((cat) => {
              const Icon = cat.icon;
              const count = outcomes.filter((o) => o.category === cat.id).length;
              return (
                <Button
                  key={cat.id}
                  variant={activeFilter === cat.id ? "default" : "outline"}
                  size="sm"
                  onClick={() => setActiveFilter(cat.id)}
                  className="gap-1"
                >
                  <Icon className="h-3 w-3" />
                  {cat.label}
                  <span className="text-xs opacity-70">({count})</span>
                </Button>
              );
            })}
          </div>
        </div>

        {/* Sync Status Panel */}
        {syncStatus &&
          (syncStatus.orphan_prompts > 0 || syncStatus.outcomes_without_prompt > 0) && (
            <Card className="mb-6 border-amber-200 bg-amber-50">
              <CardContent className="py-4">
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-4">
                    <div className="flex h-10 w-10 items-center justify-center rounded-full bg-amber-100">
                      <Link2 className="h-5 w-5 text-amber-600" />
                    </div>
                    <div>
                      <h3 className="font-medium text-amber-800">Senkronizasyon Gerekli</h3>
                      <p className="text-sm text-amber-600">
                        {syncStatus.orphan_prompts > 0 && (
                          <span className="mr-3">ÔÜá´©Å {syncStatus.orphan_prompts} yetim prompt</span>
                        )}
                        {syncStatus.outcomes_without_prompt > 0 && (
                          <span>
                            ÔÜá´©Å {syncStatus.outcomes_without_prompt} kazan─▒m─▒n promptu eksik
                          </span>
                        )}
                      </p>
                    </div>
                  </div>
                  <div className="flex items-center gap-2">
                    <Button
                      variant="outline"
                      size="sm"
                      onClick={() => router.push("/admin/prompts")}
                    >
                      <ExternalLink className="mr-1 h-4 w-4" />
                      Promptlar─▒ G├Âr
                    </Button>
                    <Button
                      size="sm"
                      onClick={executeSync}
                      disabled={syncing}
                      className="bg-amber-600 hover:bg-amber-700"
                    >
                      {syncing ? (
                        <>
                          <RotateCw className="mr-1 h-4 w-4 animate-spin" />
                          Senkronize Ediliyor...
                        </>
                      ) : (
                        <>
                          <RefreshCw className="mr-1 h-4 w-4" />
                          Senkronize Et
                        </>
                      )}
                    </Button>
                  </div>
                </div>
                {syncStatus.orphan_prompts > 0 && (
                  <div className="mt-3 border-t border-amber-200 pt-3">
                    <p className="mb-2 text-xs text-amber-700">Silinecek yetim promptlar:</p>
                    <div className="flex flex-wrap gap-1">
                      {syncStatus.orphan_prompt_list.map((p) => (
                        <code
                          key={p.id}
                          className="rounded bg-amber-100 px-1.5 py-0.5 text-xs text-amber-800"
                        >
                          {p.key}
                        </code>
                      ))}
                    </div>
                  </div>
                )}
              </CardContent>
            </Card>
          )}

        {/* Outcomes Grid */}
        {loading ? (
          <div className="py-12 text-center">
            <RotateCw className="mx-auto mb-4 h-8 w-8 animate-spin text-purple-600" />
            <p className="text-gray-500">Y├╝kleniyor...</p>
          </div>
        ) : outcomes.length === 0 ? (
          <Card className="border-2 border-dashed">
            <CardContent className="py-16 text-center">
              <Target className="mx-auto mb-4 h-16 w-16 text-gray-300" />
              <h3 className="mb-2 text-xl font-semibold text-gray-700">Hen├╝z kazan─▒m yok</h3>
              <p className="mb-6 text-gray-500">─░lk e─şitim kazan─▒m─▒n─▒z─▒ olu┼şturun</p>
              <Button onClick={() => openEditor()} className="bg-purple-600 hover:bg-purple-700">
                <Plus className="mr-2 h-4 w-4" />
                ─░lk Kazan─▒m─▒ Olu┼ştur
              </Button>
            </CardContent>
          </Card>
        ) : (
          <div className="space-y-8">
            {Object.entries(groupedOutcomes).map(([category, items]) => {
              const cat = CATEGORIES.find((c) => c.id === category);
              const Icon = cat?.icon || Sparkles;

              return (
                <div key={category}>
                  {/* Category Header */}
                  <div className="mb-4 flex items-center gap-3">
                    <div
                      className="flex h-10 w-10 items-center justify-center rounded-xl"
                      style={{ backgroundColor: `${cat?.color || "#8B5CF6"}20` }}
                    >
                      <Icon className="h-5 w-5" style={{ color: cat?.color || "#8B5CF6" }} />
                    </div>
                    <div>
                      <h2 className="font-semibold text-gray-900">{cat?.label || category}</h2>
                      <p className="text-sm text-gray-500">{items.length} kazan─▒m</p>
                    </div>
                  </div>

                  {/* Items Grid */}
                  <div className="grid grid-cols-1 gap-4 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4">
                    {items
                      .sort((a, b) => a.display_order - b.display_order)
                      .map((outcome) => {
                        const color = outcome.color_theme || cat?.color || "#8B5CF6";

                        return (
                          <Card
                            key={outcome.id}
                            className={`group overflow-hidden transition-all hover:shadow-lg ${
                              !outcome.is_active ? "opacity-60" : ""
                            }`}
                          >
                            <CardContent className="p-4">
                              {/* Header */}
                              <div className="mb-3 flex items-start gap-3">
                                <div
                                  className="flex h-10 w-10 flex-shrink-0 items-center justify-center rounded-lg"
                                  style={{ backgroundColor: `${color}20` }}
                                >
                                  {outcome.icon_url ? (
                                    <img src={outcome.icon_url} alt="" className="h-6 w-6" />
                                  ) : (
                                    <Icon className="h-5 w-5" style={{ color }} />
                                  )}
                                </div>
                                <div className="min-w-0 flex-1">
                                  <h3 className="truncate font-medium text-gray-900">
                                    {outcome.name}
                                  </h3>
                                  <p className="line-clamp-1 text-xs text-gray-500">
                                    {outcome.description || "A├ğ─▒klama yok"}
                                  </p>
                                </div>
                              </div>

                              {/* AI Instruction indicator with link to prompt */}
                              <div className="mb-3 flex items-center gap-1 text-xs text-purple-600">
                                <Brain className="h-3 w-3" />
                                <button
                                  onClick={() =>
                                    router.push(
                                      `/admin/prompts?highlight=${getPromptKeyFromName(outcome.name)}`
                                    )
                                  }
                                  className="flex items-center gap-1 truncate hover:underline"
                                >
                                  {outcome.effective_ai_instruction
                                    ? "AI talimat─▒ tan─▒ml─▒"
                                    : "Prompt d├╝zenle"}
                                  <ExternalLink className="h-3 w-3" />
                                </button>
                              </div>

                              {/* Meta */}
                              <div className="mb-3 flex items-center gap-2 text-xs text-gray-400">
                                <span className="flex items-center gap-1">
                                  <GripVertical className="h-3 w-3" />#{outcome.display_order}
                                </span>
                                <span>ÔÇó</span>
                                <span>{outcome.age_group} ya┼ş</span>
                                {!outcome.is_active && (
                                  <>
                                    <span>ÔÇó</span>
                                    <span className="text-amber-600">Pasif</span>
                                  </>
                                )}
                              </div>

                              {/* Actions */}
                              <div className="flex items-center gap-2">
                                <Button
                                  size="sm"
                                  variant="outline"
                                  className="flex-1 text-xs"
                                  onClick={() => openEditor(outcome)}
                                >
                                  <Pencil className="mr-1 h-3 w-3" />
                                  D├╝zenle
                                </Button>
                                <Button
                                  size="sm"
                                  variant="ghost"
                                  onClick={() => handleDuplicate(outcome.id)}
                                >
                                  <Copy className="h-3 w-3" />
                                </Button>
                                <Button
                                  size="sm"
                                  variant="ghost"
                                  onClick={() => toggleActive(outcome)}
                                >
                                  {outcome.is_active ? (
                                    <EyeOff className="h-3 w-3" />
                                  ) : (
                                    <Eye className="h-3 w-3" />
                                  )}
                                </Button>
                                <Button
                                  size="sm"
                                  variant="ghost"
                                  className="text-red-500 hover:bg-red-50 hover:text-red-700"
                                  onClick={() => setDeleteConfirm(outcome.id)}
                                >
                                  <Trash2 className="h-3 w-3" />
                                </Button>
                              </div>
                            </CardContent>
                          </Card>
                        );
                      })}
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </main>

      {/* Delete Confirmation */}
      <AnimatePresence>
        {deleteConfirm && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 z-50 flex items-center justify-center p-4"
            onClick={() => setDeleteConfirm(null)}
          >
            <div className="absolute inset-0 bg-black/50" />
            <motion.div
              initial={{ scale: 0.95 }}
              animate={{ scale: 1 }}
              exit={{ scale: 0.95 }}
              onClick={(e) => e.stopPropagation()}
              className="relative w-full max-w-sm rounded-2xl bg-white p-6 shadow-2xl"
            >
              <div className="text-center">
                <div className="mx-auto mb-4 flex h-12 w-12 items-center justify-center rounded-full bg-red-100">
                  <AlertCircle className="h-6 w-6 text-red-600" />
                </div>
                <h3 className="mb-2 text-lg font-semibold">Kazan─▒m─▒ Devre D─▒┼ş─▒ B─▒rak</h3>
                <p className="mb-6 text-sm text-gray-500">
                  Bu kazan─▒m pasif duruma al─▒nacak ve m├╝┼şterilere g├Âsterilmeyecek. Emin misiniz?
                </p>
                <div className="flex gap-3">
                  <Button
                    variant="outline"
                    className="flex-1"
                    onClick={() => setDeleteConfirm(null)}
                  >
                    ─░ptal
                  </Button>
                  <Button
                    variant="destructive"
                    className="flex-1"
                    onClick={() => handleDelete(deleteConfirm)}
                  >
                    Devre D─▒┼ş─▒ B─▒rak
                  </Button>
                </div>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>

      {/* Editor Sheet */}
      <Sheet open={isEditorOpen} onOpenChange={setIsEditorOpen}>
        <SheetContent className="w-full overflow-y-auto sm:max-w-2xl">
          <SheetHeader className="mb-6">
            <SheetTitle className="flex items-center gap-2">
              <Settings2 className="h-5 w-5 text-purple-600" />
              {editingOutcome ? "Kazan─▒m─▒ D├╝zenle" : "Yeni Kazan─▒m Olu┼ştur"}
            </SheetTitle>
            <SheetDescription>
              E─şitim kazan─▒m─▒, g├Ârsel tema ve AI hikaye talimat─▒n─▒ yap─▒land─▒r─▒n
            </SheetDescription>
          </SheetHeader>

          <div className="grid gap-6 lg:grid-cols-3">
            {/* Form */}
            <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-6 lg:col-span-2">
              {/* Basic Info */}
              <div className="space-y-4">
                <div className="flex items-center gap-2 text-sm font-medium text-gray-700">
                  <FileText className="h-4 w-4 text-purple-600" />
                  Temel Bilgiler
                </div>

                <div>
                  <Label>Kazan─▒m Ad─▒ *</Label>
                  <Input
                    {...form.register("name")}
                    placeholder="├ûrn: Do─şa Sevgisi"
                    className="mt-1"
                  />
                  {form.formState.errors.name && (
                    <p className="mt-1 text-xs text-red-500">
                      {form.formState.errors.name.message}
                    </p>
                  )}
                </div>

                <div>
                  <Label>A├ğ─▒klama</Label>
                  <Textarea
                    {...form.register("description")}
                    placeholder="Kazan─▒m hakk─▒nda k─▒sa a├ğ─▒klama"
                    rows={2}
                    className="mt-1"
                  />
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <Label>Kategori *</Label>
                    <Controller
                      control={form.control}
                      name="category"
                      render={({ field }) => (
                        <Select
                          value={field.value}
                          onValueChange={(val) => {
                            field.onChange(val);
                            const cat = CATEGORIES.find((c) => c.id === val);
                            if (cat) {
                              form.setValue("category_label", cat.label);
                              if (!form.getValues("color_theme")) {
                                form.setValue("color_theme", cat.color);
                              }
                            }
                          }}
                        >
                          <SelectTrigger className="mt-1">
                            <SelectValue />
                          </SelectTrigger>
                          <SelectContent>
                            {CATEGORIES.map((cat) => {
                              const Icon = cat.icon;
                              return (
                                <SelectItem key={cat.id} value={cat.id}>
                                  <div className="flex items-center gap-2">
                                    <Icon className="h-4 w-4" style={{ color: cat.color }} />
                                    {cat.label}
                                  </div>
                                </SelectItem>
                              );
                            })}
                          </SelectContent>
                        </Select>
                      )}
                    />
                  </div>
                  <div>
                    <Label>Ya┼ş Grubu</Label>
                    <Controller
                      control={form.control}
                      name="age_group"
                      render={({ field }) => (
                        <Select value={field.value} onValueChange={field.onChange}>
                          <SelectTrigger className="mt-1">
                            <SelectValue />
                          </SelectTrigger>
                          <SelectContent>
                            <SelectItem value="3-6">3-6 ya┼ş</SelectItem>
