  product_price: number | null;
  page_count: number;
  page_images: { [key: string]: string } | null;
  confirmed_at: string | null;
  created_at: string;
}

interface Stats {
  total_orders: number;
  pending_orders: number;
  confirmed_orders: number;
  total_revenue: number;
