  const fetchOrders = async () => {
    try {
      // Fetch stats from dedicated endpoint
      const statsRes = await fetch(`${API_BASE_URL}/admin/orders/stats/previews`, {
        headers: getAuthHeaders(),
      });
      if (statsRes.ok) {
        const statsData = await statsRes.json();
        setStats({
          total_orders: statsData.total ?? 0,
          pending_orders: statsData.pending ?? 0,
          confirmed_orders: statsData.confirmed ?? 0,
          total_revenue: statsData.total_revenue ?? 0,
        });
      }

      // Fetch recent previews
      const response = await fetch(`${API_BASE_URL}/admin/orders/previews`, {
        headers: getAuthHeaders(),
      });
      if (response.ok) {
        const raw = await response.json();
        const data: StoryPreview[] = Array.isArray(raw) ? raw : (raw.items ?? []);
        setOrders(data);
      } else {
        toast({
          title: "Veri al─▒namad─▒",
          description: `Backend ${response.status} d├Ând├╝. L├╝tfen backend'in ├ğal─▒┼şt─▒─ş─▒ndan emin olun.`,
          variant: "destructive",
        });
      }
    } catch (error) {
      console.error("Failed to fetch orders:", error);
      toast({
        title: "Backend'e ba─şlan─▒lamad─▒",
        description: "API sunucusu yan─▒t vermiyor. Docker/backend ├ğal─▒┼ş─▒yor mu kontrol edin.",
        variant: "destructive",
      });
    } finally {
      setLoading(false);
