  max_page_count: number;
  // Paper & Cover
  paper_type: string;
  paper_finish: string;
  cover_type: string;
  lamination: string | null;
  // Pricing
  base_price: number;
  discounted_price?: number | null;
  extra_page_price: number;
  discount_percentage?: number | null;
  vat_rate?: number;
  // Status
