        toast({ title: "Ba┼şar─▒l─▒", description: "├£r├╝n kopyaland─▒" });
        fetchData();
      } else {
        toast({ title: "Hata", description: "Kopyalama ba┼şar─▒s─▒z", variant: "destructive" });
      }
    } catch {
      toast({ title: "Hata", description: "Kopyalama ba┼şar─▒s─▒z", variant: "destructive" });
    } finally {
      setOperatingId(null);
    }
  };

  const toggleActive = async (product: Product) => {
