"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { Button } from "@/components/ui/button";
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Switch } from "@/components/ui/switch";
import { Badge } from "@/components/ui/badge";
import { useToast } from "@/hooks/use-toast";
import {
  ArrowLeft,
  Plus,
  Edit,
  Trash2,
  Ticket,
  Search,
  Copy,
  Wand2,
} from "lucide-react";
import Link from "next/link";
import { API_BASE_URL } from "@/lib/api";
import { getAdminHeaders as getAuthHeaders } from "@/lib/adminFetch";

// ÔöÇÔöÇÔöÇ Types ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

interface PromoCode {
  id: string;
  code: string;
  discount_type: "PERCENT" | "AMOUNT";
  discount_value: number;
  usage_limit: number;
  used_count: number;
  is_active: boolean;
  valid_from: string | null;
  valid_until: string | null;
  min_order_amount: number | null;
  max_discount_amount: number | null;
  notes: string | null;
  created_by: string | null;
  created_at: string;
  updated_at: string;
}

interface FormData {
  code: string;
  discount_type: "PERCENT" | "AMOUNT";
  discount_value: string;
  usage_limit: string;
  valid_from: string;
  valid_until: string;
  min_order_amount: string;
  max_discount_amount: string;
  notes: string;
}

interface BulkFormData {
  count: string;
  discount_type: "PERCENT" | "AMOUNT";
  discount_value: string;
  usage_limit: string;
  valid_from: string;
  valid_until: string;
  min_order_amount: string;
  max_discount_amount: string;
  prefix: string;
  notes: string;
}

const defaultFormData: FormData = {
  code: "",
  discount_type: "PERCENT",
  discount_value: "",
  usage_limit: "1",
  valid_from: "",
  valid_until: "",
  min_order_amount: "",
  max_discount_amount: "",
  notes: "",
};

const defaultBulkFormData: BulkFormData = {
  count: "10",
  discount_type: "PERCENT",
  discount_value: "",
  usage_limit: "1",
  valid_from: "",
  valid_until: "",
  min_order_amount: "",
  max_discount_amount: "",
  prefix: "",
  notes: "",
};

// ÔöÇÔöÇÔöÇ Page ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

export default function AdminPromoCodesPage() {
  const [promoCodes, setPromoCodes] = useState<PromoCode[]>([]);
  const [loading, setLoading] = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [showBulkForm, setShowBulkForm] = useState(false);
  const [editingPromo, setEditingPromo] = useState<PromoCode | null>(null);
  const [saving, setSaving] = useState(false);
  const [formData, setFormData] = useState<FormData>(defaultFormData);
  const [bulkFormData, setBulkFormData] =
    useState<BulkFormData>(defaultBulkFormData);
  const [searchQuery, setSearchQuery] = useState("");
  const [filterActive, setFilterActive] = useState<boolean | null>(null);
  const [totalCount, setTotalCount] = useState(0);
  const [currentPage, setCurrentPage] = useState(1);
  const pageSize = 20;

  const router = useRouter();
  const { toast } = useToast();

  useEffect(() => {
    checkAuth();
    fetchPromoCodes();
  }, [currentPage, filterActive, searchQuery]);

  const checkAuth = () => {
    const user = localStorage.getItem("user");
    if (!user) {
      router.push("/auth/login");
      return;
    }
    const userData = JSON.parse(user);
    if (userData.role !== "admin") {
      toast({
        title: "Yetkisiz Eri┼şim",
        description: "Bu sayfaya eri┼şim yetkiniz yok",
        variant: "destructive",
      });
      router.push("/");
    }
  };


  // ÔöÇÔöÇÔöÇ API Calls ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  const fetchPromoCodes = async () => {
    try {
      const token = localStorage.getItem("token");
      if (!token) {
        router.push("/auth/login");
        return;
      }

      const params = new URLSearchParams({
        page: String(currentPage),
        page_size: String(pageSize),
      });
      if (filterActive !== null) params.set("is_active", String(filterActive));
      if (searchQuery.trim()) params.set("search", searchQuery.trim());

      const response = await fetch(
        `${API_BASE_URL}/admin/promo-codes?${params}`,
        { headers: getAuthHeaders() }
      );

      if (response.status === 401) {
        localStorage.removeItem("token");
        router.push("/auth/login");
        return;
      }

      if (response.ok) {
        const data = await response.json();
        setPromoCodes(data.items);
        setTotalCount(data.total);
      } else {
        toast({
          title: "Hata",
          description: "Kupon kodlar─▒ y├╝klenemedi",
          variant: "destructive",
        });
      }
    } catch {
      toast({
        title: "Hata",
        description: "Ba─şlant─▒ hatas─▒",
        variant: "destructive",
      });
    } finally {
      setLoading(false);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!formData.discount_value || Number(formData.discount_value) <= 0) {
      toast({
        title: "Hata",
        description: "─░ndirim de─şeri girilmelidir",
        variant: "destructive",
      });
      return;
    }

    setSaving(true);
    try {
      const payload: Record<string, unknown> = {
        discount_type: formData.discount_type,
        discount_value: Number(formData.discount_value),
        usage_limit: Number(formData.usage_limit) || 1,
      };

      if (formData.code.trim()) payload.code = formData.code.trim();
      if (formData.valid_from) payload.valid_from = new Date(formData.valid_from).toISOString();
      if (formData.valid_until) payload.valid_until = new Date(formData.valid_until).toISOString();
      if (formData.min_order_amount)
        payload.min_order_amount = Number(formData.min_order_amount);
      if (formData.max_discount_amount)
        payload.max_discount_amount = Number(formData.max_discount_amount);
      if (formData.notes.trim()) payload.notes = formData.notes.trim();

      const url = editingPromo
        ? `${API_BASE_URL}/admin/promo-codes/${editingPromo.id}`
        : `${API_BASE_URL}/admin/promo-codes`;

      const response = await fetch(url, {
        method: editingPromo ? "PATCH" : "POST",
        headers: getAuthHeaders(),
        body: JSON.stringify(payload),
      });

      if (response.ok) {
        toast({
          title: "Ba┼şar─▒l─▒",
          description: editingPromo
            ? "Kupon kodu g├╝ncellendi"
            : "Kupon kodu olu┼şturuldu",
        });
        setShowForm(false);
        resetForm();
        fetchPromoCodes();
      } else {
        const err = await response.json().catch(() => null);
        toast({
          title: "Hata",
          description: err?.detail || "─░┼şlem ba┼şar─▒s─▒z oldu",
          variant: "destructive",
        });
      }
    } catch {
      toast({
        title: "Hata",
        description: "Ba─şlant─▒ hatas─▒",
        variant: "destructive",
      });
    } finally {
      setSaving(false);
    }
  };

  const handleBulkGenerate = async (e: React.FormEvent) => {
    e.preventDefault();

    if (
      !bulkFormData.discount_value ||
      Number(bulkFormData.discount_value) <= 0
    ) {
      toast({
        title: "Hata",
        description: "─░ndirim de─şeri girilmelidir",
        variant: "destructive",
      });
      return;
    }

    setSaving(true);
    try {
      const payload: Record<string, unknown> = {
        count: Number(bulkFormData.count) || 10,
        discount_type: bulkFormData.discount_type,
        discount_value: Number(bulkFormData.discount_value),
        usage_limit: Number(bulkFormData.usage_limit) || 1,
      };

      if (bulkFormData.prefix.trim())
        payload.prefix = bulkFormData.prefix.trim();
      if (bulkFormData.valid_from)
        payload.valid_from = new Date(bulkFormData.valid_from).toISOString();
      if (bulkFormData.valid_until)
        payload.valid_until = new Date(bulkFormData.valid_until).toISOString();
      if (bulkFormData.min_order_amount)
        payload.min_order_amount = Number(bulkFormData.min_order_amount);
      if (bulkFormData.max_discount_amount)
        payload.max_discount_amount = Number(bulkFormData.max_discount_amount);
      if (bulkFormData.notes.trim())
        payload.notes = bulkFormData.notes.trim();

      const response = await fetch(
        `${API_BASE_URL}/admin/promo-codes/bulk-generate`,
        {
          method: "POST",
          headers: getAuthHeaders(),
          body: JSON.stringify(payload),
        }
      );

      if (response.ok) {
        const data = await response.json();
        toast({
          title: "Ba┼şar─▒l─▒",
          description: `${data.count} adet kupon kodu olu┼şturuldu`,
        });
        setShowBulkForm(false);
        setBulkFormData(defaultBulkFormData);
        fetchPromoCodes();
      } else {
        const err = await response.json().catch(() => null);
        toast({
          title: "Hata",
          description: err?.detail || "Toplu ├╝retim ba┼şar─▒s─▒z",
          variant: "destructive",
        });
      }
    } catch {
      toast({
        title: "Hata",
        description: "Ba─şlant─▒ hatas─▒",
        variant: "destructive",
      });
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async (promoId: string) => {
    if (!confirm("Bu kupon kodunu deaktif etmek istedi─şinize emin misiniz?"))
      return;

    try {
      const response = await fetch(
        `${API_BASE_URL}/admin/promo-codes/${promoId}`,
        {
          method: "DELETE",
          headers: getAuthHeaders(),
        }
      );

      if (response.ok) {
        toast({
          title: "Ba┼şar─▒l─▒",
          description: "Kupon kodu deaktif edildi",
        });
        fetchPromoCodes();
      } else {
        toast({
          title: "Hata",
          description: "─░┼şlem ba┼şar─▒s─▒z oldu",
          variant: "destructive",
        });
      }
    } catch {
      toast({
        title: "Hata",
        description: "Ba─şlant─▒ hatas─▒",
        variant: "destructive",
      });
    }
  };

  const handleToggleActive = async (promo: PromoCode) => {
    try {
      const response = await fetch(
        `${API_BASE_URL}/admin/promo-codes/${promo.id}`,
        {
          method: "PATCH",
          headers: getAuthHeaders(),
          body: JSON.stringify({ is_active: !promo.is_active }),
        }
      );

      if (response.ok) {
        toast({
          title: "Ba┼şar─▒l─▒",
          description: promo.is_active
            ? "Kupon deaktif edildi"
            : "Kupon aktif edildi",
        });
        fetchPromoCodes();
      }
    } catch {
      toast({
        title: "Hata",
        description: "─░┼şlem ba┼şar─▒s─▒z",
        variant: "destructive",
      });
    }
  };

  // ÔöÇÔöÇÔöÇ Helpers ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  const resetForm = () => {
    setFormData(defaultFormData);
    setEditingPromo(null);
  };

  const handleEdit = (promo: PromoCode) => {
    setFormData({
      code: promo.code,
      discount_type: promo.discount_type,
      discount_value: String(promo.discount_value),
      usage_limit: String(promo.usage_limit),
      valid_from: promo.valid_from
        ? new Date(promo.valid_from).toISOString().slice(0, 16)
        : "",
      valid_until: promo.valid_until
        ? new Date(promo.valid_until).toISOString().slice(0, 16)
        : "",
      min_order_amount: promo.min_order_amount
        ? String(promo.min_order_amount)
        : "",
      max_discount_amount: promo.max_discount_amount
        ? String(promo.max_discount_amount)
        : "",
      notes: promo.notes || "",
    });
    setEditingPromo(promo);
    setShowForm(true);
    setShowBulkForm(false);
  };

  const copyCode = (code: string) => {
    navigator.clipboard.writeText(code);
    toast({ title: "Kopyaland─▒", description: `${code} panoya kopyaland─▒` });
  };

  const formatDate = (dateStr: string | null) => {
    if (!dateStr) return "-";
    return new Date(dateStr).toLocaleDateString("tr-TR", {
      day: "2-digit",
      month: "2-digit",
      year: "numeric",
    });
  };

  const formatDiscount = (promo: PromoCode) => {
    if (promo.discount_type === "PERCENT") {
      return `%${promo.discount_value}`;
    }
    return `${promo.discount_value} TL`;
  };

  const totalPages = Math.ceil(totalCount / pageSize);

  // ÔöÇÔöÇÔöÇ Render ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-[400px]">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-gray-900" />
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-3">
          <Link href="/admin">
            <Button variant="ghost" size="icon">
              <ArrowLeft className="h-5 w-5" />
            </Button>
          </Link>
          <div>
            <h1 className="text-2xl font-bold">Kupon Kodlar─▒</h1>
            <p className="text-sm text-muted-foreground">
              Toplam {totalCount} kupon kodu
            </p>
          </div>
        </div>
        <div className="flex gap-2">
          <Button
            variant="outline"
            onClick={() => {
              setShowBulkForm(true);
              setShowForm(false);
            }}
          >
            <Wand2 className="h-4 w-4 mr-2" />
            Toplu ├£ret
          </Button>
          <Button
            onClick={() => {
              resetForm();
              setShowForm(true);
              setShowBulkForm(false);
            }}
          >
            <Plus className="h-4 w-4 mr-2" />
            Yeni Kupon
          </Button>
        </div>
      </div>

      {/* Filters */}
      <Card>
        <CardContent className="pt-6">
          <div className="flex flex-wrap gap-4 items-end">
            <div className="flex-1 min-w-[200px]">
              <Label>Kod Ara</Label>
              <div className="relative">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                <Input
                  placeholder="Kupon kodu ara..."
                  value={searchQuery}
                  onChange={(e) => {
                    setSearchQuery(e.target.value);
                    setCurrentPage(1);
                  }}
                  className="pl-9"
                />
              </div>
            </div>
            <div className="flex gap-2">
              <Button
                variant={filterActive === null ? "default" : "outline"}
                size="sm"
                onClick={() => {
                  setFilterActive(null);
                  setCurrentPage(1);
                }}
              >
                T├╝m├╝
              </Button>
              <Button
                variant={filterActive === true ? "default" : "outline"}
                size="sm"
                onClick={() => {
                  setFilterActive(true);
                  setCurrentPage(1);
                }}
              >
                Aktif
              </Button>
              <Button
                variant={filterActive === false ? "default" : "outline"}
                size="sm"
                onClick={() => {
                  setFilterActive(false);
                  setCurrentPage(1);
                }}
              >
                Pasif
              </Button>
            </div>
          </div>
        </CardContent>
      </Card>

      {/* Create / Edit Form */}
      {showForm && (
        <Card>
          <CardHeader>
            <CardTitle>
              {editingPromo ? "Kuponu D├╝zenle" : "Yeni Kupon Kodu"}
            </CardTitle>
            <CardDescription>
              {editingPromo
                ? `${editingPromo.code} kuponunu d├╝zenliyorsunuz`
                : "Kod bo┼ş b─▒rak─▒l─▒rsa otomatik ├╝retilir"}
            </CardDescription>
          </CardHeader>
          <CardContent>
            <form onSubmit={handleSubmit} className="space-y-4">
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                {/* Code */}
                {!editingPromo && (
                  <div>
                    <Label>Kupon Kodu (opsiyonel)</Label>
                    <Input
                      placeholder="Bo┼ş b─▒rak─▒n = otomatik ├╝retilir"
                      value={formData.code}
                      onChange={(e) =>
                        setFormData({
                          ...formData,
                          code: e.target.value.toUpperCase(),
                        })
                      }
                      maxLength={50}
                    />
                  </div>
                )}

                {/* Discount Type */}
                <div>
                  <Label>─░ndirim Tipi</Label>
                  <select
                    className="flex h-10 w-full rounded-md border border-input bg-background px-3 py-2 text-sm"
                    value={formData.discount_type}
                    onChange={(e) =>
                      setFormData({
                        ...formData,
                        discount_type: e.target.value as "PERCENT" | "AMOUNT",
                      })
                    }
                  >
                    <option value="PERCENT">Y├╝zde (%)</option>
                    <option value="AMOUNT">Sabit Tutar (TL)</option>
                  </select>
                </div>

                {/* Discount Value */}
                <div>
                  <Label>
                    ─░ndirim De─şeri{" "}
                    {formData.discount_type === "PERCENT" ? "(%)" : "(TL)"}
                  </Label>
                  <Input
                    type="number"
                    placeholder={
                      formData.discount_type === "PERCENT" ? "1-100" : "Tutar"
                    }
                    value={formData.discount_value}
                    onChange={(e) =>
                      setFormData({ ...formData, discount_value: e.target.value })
                    }
                    min={formData.discount_type === "PERCENT" ? 1 : 0.01}
                    max={formData.discount_type === "PERCENT" ? 100 : undefined}
                    step="0.01"
                    required
                  />
                </div>

                {/* Usage Limit */}
                <div>
                  <Label>Kullan─▒m Limiti</Label>
                  <Input
                    type="number"
                    placeholder="1"
                    value={formData.usage_limit}
                    onChange={(e) =>
                      setFormData({ ...formData, usage_limit: e.target.value })
                    }
                    min={1}
                    required
                  />
                </div>

                {/* Valid From */}
                <div>
                  <Label>Ba┼şlang─▒├ğ Tarihi (opsiyonel)</Label>
                  <Input
                    type="datetime-local"
                    value={formData.valid_from}
                    onChange={(e) =>
                      setFormData({ ...formData, valid_from: e.target.value })
                    }
                  />
                </div>

                {/* Valid Until */}
                <div>
                  <Label>Biti┼ş Tarihi (opsiyonel)</Label>
                  <Input
                    type="datetime-local"
                    value={formData.valid_until}
                    onChange={(e) =>
                      setFormData({ ...formData, valid_until: e.target.value })
                    }
                  />
                </div>

                {/* Min Order Amount */}
                <div>
                  <Label>Minimum Sipari┼ş Tutar─▒ (opsiyonel)</Label>
                  <Input
                    type="number"
                    placeholder="0"
                    value={formData.min_order_amount}
                    onChange={(e) =>
                      setFormData({
                        ...formData,
                        min_order_amount: e.target.value,
                      })
                    }
                    min={0}
                    step="0.01"
                  />
                </div>

                {/* Max Discount Amount */}
                <div>
                  <Label>Maksimum ─░ndirim Tutar─▒ (opsiyonel)</Label>
                  <Input
                    type="number"
                    placeholder="Tavan indirim"
                    value={formData.max_discount_amount}
                    onChange={(e) =>
                      setFormData({
                        ...formData,
                        max_discount_amount: e.target.value,
                      })
                    }
                    min={0}
                    step="0.01"
                  />
                </div>
              </div>

              {/* Notes */}
              <div>
                <Label>Notlar (opsiyonel)</Label>
                <Textarea
                  placeholder="Admin notlar─▒..."
                  value={formData.notes}
                  onChange={(e) =>
                    setFormData({ ...formData, notes: e.target.value })
                  }
                  rows={2}
                />
              </div>

              {/* Actions */}
              <div className="flex gap-2">
                <Button type="submit" disabled={saving}>
                  {saving && "Kaydediliyor..."}
                  {!saving && editingPromo && "G├╝ncelle"}
                  {!saving && !editingPromo && "Olu┼ştur"}
                </Button>
                <Button
                  type="button"
                  variant="outline"
                  onClick={() => {
                    setShowForm(false);
                    resetForm();
                  }}
                >
                  ─░ptal
                </Button>
              </div>
            </form>
          </CardContent>
        </Card>
      )}

      {/* Bulk Generate Form */}
      {showBulkForm && (
        <Card>
          <CardHeader>
            <CardTitle>Toplu Kupon ├£retimi</CardTitle>
            <CardDescription>
              Ayn─▒ ayarlarla birden fazla kupon kodu ├╝retin
            </CardDescription>
          </CardHeader>
          <CardContent>
            <form onSubmit={handleBulkGenerate} className="space-y-4">
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                {/* Count */}
                <div>
                  <Label>Adet</Label>
                  <Input
                    type="number"
                    value={bulkFormData.count}
                    onChange={(e) =>
                      setBulkFormData({ ...bulkFormData, count: e.target.value })
                    }
                    min={1}
                    max={100}
                    required
                  />
                </div>

                {/* Prefix */}
                <div>
                  <Label>├ûn Ek (opsiyonel)</Label>
                  <Input
                    placeholder="KAMPANYA"
                    value={bulkFormData.prefix}
                    onChange={(e) =>
                      setBulkFormData({
                        ...bulkFormData,
                        prefix: e.target.value.toUpperCase(),
                      })
                    }
                    maxLength={10}
                  />
                </div>

                {/* Discount Type */}
                <div>
                  <Label>─░ndirim Tipi</Label>
                  <select
                    className="flex h-10 w-full rounded-md border border-input bg-background px-3 py-2 text-sm"
                    value={bulkFormData.discount_type}
                    onChange={(e) =>
                      setBulkFormData({
                        ...bulkFormData,
                        discount_type: e.target.value as "PERCENT" | "AMOUNT",
                      })
                    }
                  >
                    <option value="PERCENT">Y├╝zde (%)</option>
                    <option value="AMOUNT">Sabit Tutar (TL)</option>
                  </select>
                </div>

                {/* Discount Value */}
                <div>
                  <Label>
                    ─░ndirim De─şeri{" "}
                    {bulkFormData.discount_type === "PERCENT" ? "(%)" : "(TL)"}
                  </Label>
                  <Input
                    type="number"
                    value={bulkFormData.discount_value}
                    onChange={(e) =>
                      setBulkFormData({
                        ...bulkFormData,
                        discount_value: e.target.value,
                      })
                    }
                    min={bulkFormData.discount_type === "PERCENT" ? 1 : 0.01}
                    max={
                      bulkFormData.discount_type === "PERCENT" ? 100 : undefined
                    }
                    step="0.01"
                    required
                  />
                </div>

                {/* Usage Limit */}
                <div>
                  <Label>Her Kuponun Kullan─▒m Limiti</Label>
                  <Input
                    type="number"
                    value={bulkFormData.usage_limit}
                    onChange={(e) =>
                      setBulkFormData({
                        ...bulkFormData,
                        usage_limit: e.target.value,
                      })
                    }
                    min={1}
                    required
                  />
                </div>

                {/* Valid From */}
                <div>
                  <Label>Ba┼şlang─▒├ğ Tarihi (opsiyonel)</Label>
                  <Input
                    type="datetime-local"
                    value={bulkFormData.valid_from}
                    onChange={(e) =>
                      setBulkFormData({
                        ...bulkFormData,
                        valid_from: e.target.value,
                      })
                    }
                  />
                </div>

                {/* Valid Until */}
                <div>
                  <Label>Biti┼ş Tarihi (opsiyonel)</Label>
                  <Input
                    type="datetime-local"
                    value={bulkFormData.valid_until}
                    onChange={(e) =>
                      setBulkFormData({
                        ...bulkFormData,
                        valid_until: e.target.value,
                      })
                    }
                  />
                </div>

                {/* Max Discount Amount */}
                <div>
                  <Label>Maks ─░ndirim Tutar─▒ (opsiyonel)</Label>
                  <Input
                    type="number"
                    placeholder="Tavan indirim"
                    value={bulkFormData.max_discount_amount}
                    onChange={(e) =>
                      setBulkFormData({
                        ...bulkFormData,
                        max_discount_amount: e.target.value,
                      })
                    }
                    min={0}
                    step="0.01"
                  />
                </div>
              </div>

              {/* Notes */}
              <div>
                <Label>Notlar (opsiyonel)</Label>
                <Textarea
                  placeholder="Admin notlar─▒..."
                  value={bulkFormData.notes}
                  onChange={(e) =>
                    setBulkFormData({ ...bulkFormData, notes: e.target.value })
                  }
                  rows={2}
                />
              </div>

              {/* Actions */}
              <div className="flex gap-2">
                <Button type="submit" disabled={saving}>
                  {saving ? "├£retiliyor..." : "Toplu ├£ret"}
                </Button>
                <Button
                  type="button"
                  variant="outline"
                  onClick={() => {
                    setShowBulkForm(false);
                    setBulkFormData(defaultBulkFormData);
                  }}
                >
                  ─░ptal
                </Button>
              </div>
            </form>
          </CardContent>
        </Card>
      )}

      {/* Table */}
      <Card>
        <CardContent className="pt-6">
          {promoCodes.length === 0 ? (
            <div className="text-center py-12 text-muted-foreground">
              <Ticket className="h-12 w-12 mx-auto mb-4 opacity-50" />
              <p>Hen├╝z kupon kodu bulunmuyor</p>
            </div>
          ) : (
            <div className="overflow-x-auto">
              <table className="w-full text-sm">
                <thead>
                  <tr className="border-b text-left">
                    <th className="pb-3 font-medium">Kod</th>
                    <th className="pb-3 font-medium">─░ndirim</th>
                    <th className="pb-3 font-medium">Kullan─▒m</th>
                    <th className="pb-3 font-medium">Durum</th>
                    <th className="pb-3 font-medium">Ge├ğerlilik</th>
                    <th className="pb-3 font-medium">Min. Tutar</th>
                    <th className="pb-3 font-medium text-right">─░┼şlemler</th>
                  </tr>
                </thead>
                <tbody>
                  {promoCodes.map((promo) => (
                    <tr
                      key={promo.id}
                      className="border-b last:border-0 hover:bg-muted/50"
                    >
                      {/* Code */}
                      <td className="py-3">
                        <div className="flex items-center gap-2">
                          <code className="font-mono font-bold text-sm bg-muted px-2 py-0.5 rounded">
                            {promo.code}
                          </code>
                          <button
                            onClick={() => copyCode(promo.code)}
                            className="text-muted-foreground hover:text-foreground"
                            title="Kopyala"
                          >
                            <Copy className="h-3.5 w-3.5" />
                          </button>
                        </div>
                      </td>

                      {/* Discount */}
                      <td className="py-3">
                        <Badge variant="secondary">
                          {formatDiscount(promo)}
                        </Badge>
                        {promo.max_discount_amount && (
                          <span className="text-xs text-muted-foreground ml-1">
                            (maks {promo.max_discount_amount} TL)
                          </span>
                        )}
                      </td>

                      {/* Usage */}
                      <td className="py-3">
                        <span
                          className={
                            promo.used_count >= promo.usage_limit
                              ? "text-red-600 font-medium"
                              : ""
                          }
                        >
                          {promo.used_count} / {promo.usage_limit}
                        </span>
                      </td>

                      {/* Status */}
                      <td className="py-3">
                        <div className="flex items-center gap-2">
                          <Switch
                            checked={promo.is_active}
                            onCheckedChange={() => handleToggleActive(promo)}
                          />
                          <Badge
                            variant={promo.is_active ? "default" : "outline"}
                          >
                            {promo.is_active ? "Aktif" : "Pasif"}
                          </Badge>
                        </div>
                      </td>

                      {/* Validity */}
                      <td className="py-3 text-xs">
                        {promo.valid_from || promo.valid_until ? (
                          <>
                            {formatDate(promo.valid_from)} -{" "}
                            {formatDate(promo.valid_until)}
                          </>
                        ) : (
                          <span className="text-muted-foreground">
                            S├╝resiz
                          </span>
                        )}
                      </td>

                      {/* Min Amount */}
                      <td className="py-3">
                        {promo.min_order_amount
                          ? `${promo.min_order_amount} TL`
                          : "-"}
                      </td>

                      {/* Actions */}
                      <td className="py-3 text-right">
                        <div className="flex justify-end gap-1">
                          <Button
                            variant="ghost"
                            size="icon"
                            onClick={() => handleEdit(promo)}
                            title="D├╝zenle"
                          >
                            <Edit className="h-4 w-4" />
                          </Button>
                          {promo.is_active && (
                            <Button
                              variant="ghost"
                              size="icon"
                              onClick={() => handleDelete(promo.id)}
                              title="Deaktif Et"
                              className="text-red-600 hover:text-red-700"
                            >
                              <Trash2 className="h-4 w-4" />
                            </Button>
                          )}
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}

          {/* Pagination */}
          {totalPages > 1 && (
            <div className="flex items-center justify-between mt-4 pt-4 border-t">
              <p className="text-sm text-muted-foreground">
                Sayfa {currentPage} / {totalPages}
              </p>
              <div className="flex gap-2">
                <Button
                  variant="outline"
                  size="sm"
                  disabled={currentPage <= 1}
                  onClick={() => setCurrentPage((p) => p - 1)}
                >
                  ├ûnceki
                </Button>
                <Button
                  variant="outline"
                  size="sm"
                  disabled={currentPage >= totalPages}
                  onClick={() => setCurrentPage((p) => p + 1)}
                >
                  Sonraki
                </Button>
              </div>
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { motion, AnimatePresence } from "framer-motion";
import {
  Plus,
  Pencil,
  Trash2,
  CheckCircle2,
  AlertCircle,
  RotateCw,
  Wand2,
  FileText,
  Code,
  Copy,
  RefreshCw,
  BookOpen,
  Palette,
  Target,
  Image,
  ExternalLink,
  Link2,
} from "lucide-react";

import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Badge } from "@/components/ui/badge";
import { Separator } from "@/components/ui/separator";
import {
  Sheet,
  SheetContent,
  SheetDescription,
  SheetHeader,
  SheetTitle,
} from "@/components/ui/sheet";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { useToast } from "@/hooks/use-toast";
import { API_BASE_URL } from "@/lib/api";
import { getAdminHeaders as getAuthHeaders } from "@/lib/adminFetch";

// ============ TYPES ============
interface PromptTemplate {
  id: string;
  key: string;
  name: string;
  category: string;
  description: string | null;
  content: string;
  content_en: string | null;
  version: number;
  is_active: boolean;
  modified_by: string | null;
  created_at: string | null;
  updated_at: string | null;
}

const CATEGORY_CONFIG: Record<
  string,
  { label: string; icon: React.ReactNode; color: string }
> = {
  story_system: {
    label: "Hikaye Sistemi",
    icon: <BookOpen className="h-4 w-4" />,
    color: "purple",
  },
  visual_template: {
    label: "G├Ârsel ┼Şablon",
    icon: <Palette className="h-4 w-4" />,
    color: "blue",
  },
  negative_prompt: {
    label: "Negatif Prompt",
    // eslint-disable-next-line jsx-a11y/alt-text
    icon: <Image className="h-4 w-4" aria-hidden />,
    color: "red",
  },
  educational: {
    label: "E─şitsel De─şerler",
    icon: <Target className="h-4 w-4" />,
    color: "green",
  },
};

export default function AdminPromptsPage() {
  const [prompts, setPrompts] = useState<PromptTemplate[]>([]);
  const [loading, setLoading] = useState(true);
  const [isEditorOpen, setIsEditorOpen] = useState(false);
  const [editingPrompt, setEditingPrompt] = useState<PromptTemplate | null>(
    null
  );
  const [deleteConfirm, setDeleteConfirm] = useState<string | null>(null);
  const [selectedCategory, setSelectedCategory] = useState<string | null>(null);
  const [cacheStats, setCacheStats] = useState<{
    total: number;
    active: number;
  } | null>(null);

  const [formData, setFormData] = useState({
    key: "",
    name: "",
    category: "story_system",
    description: "",
    content: "",
    content_en: "",
  });

  const router = useRouter();
  const { toast } = useToast();

  useEffect(() => {
    checkAuth();
    fetchPrompts();
    fetchCacheStats();
  }, []);

  const checkAuth = () => {
    const user = localStorage.getItem("user");
    if (!user) {
      router.push("/auth/login");
      return;
    }
    const userData = JSON.parse(user);
    if (userData.role !== "admin") {
      router.push("/");
    }
  };


  const fetchPrompts = async () => {
    try {
      const response = await fetch(`${API_BASE_URL}/admin/prompts`, {
        headers: getAuthHeaders(),
      });
      if (response.status === 401) {
        router.push("/auth/login");
        return;
      }
      if (response.ok) {
        const data = await response.json();
        setPrompts(data.prompts || []);
      }
    } catch {
      toast({
        title: "Hata",
        description: "Promptlar y├╝klenemedi",
        variant: "destructive",
      });
    } finally {
      setLoading(false);
    }
  };

  const fetchCacheStats = async () => {
    try {
      const response = await fetch(
        `${API_BASE_URL}/admin/prompts/cache-stats`,
        { headers: getAuthHeaders() }
      );
      if (response.ok) {
        const data = await response.json();
        setCacheStats(data);
      }
    } catch {
      // ignore
    }
  };

  const clearCache = async () => {
    try {
      const response = await fetch(
        `${API_BASE_URL}/admin/prompts/clear-cache`,
        { method: "POST", headers: getAuthHeaders() }
      );
      if (response.ok) {
        toast({ title: "Ba┼şar─▒l─▒", description: "Cache temizlendi" });
        fetchCacheStats();
      }
    } catch {
      toast({
        title: "Hata",
        description: "Cache temizlenemedi",
        variant: "destructive",
      });
    }
  };

  const openEditor = (prompt?: PromptTemplate) => {
    if (prompt) {
      setEditingPrompt(prompt);
      setFormData({
        key: prompt.key,
        name: prompt.name,
        category: prompt.category,
        description: prompt.description || "",
        content: prompt.content,
        content_en: prompt.content_en || "",
      });
    } else {
      setEditingPrompt(null);
      setFormData({
        key: "",
        name: "",
        category: "story_system",
        description: "",
        content: "",
        content_en: "",
      });
    }
    setIsEditorOpen(true);
  };

  const closeEditor = () => {
    setIsEditorOpen(false);
    setEditingPrompt(null);
    setFormData({
      key: "",
      name: "",
      category: "story_system",
      description: "",
      content: "",
      content_en: "",
    });
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      const url = editingPrompt
        ? `${API_BASE_URL}/admin/prompts/${editingPrompt.key}`
        : `${API_BASE_URL}/admin/prompts`;

      const payload = editingPrompt
        ? {
            name: formData.name,
            description: formData.description,
            content: formData.content,
            content_en: formData.content_en || null,
          }
        : { ...formData, content_en: formData.content_en || null };

      const response = await fetch(url, {
        method: editingPrompt ? "PUT" : "POST",
        headers: getAuthHeaders(),
        body: JSON.stringify(payload),
      });

      if (response.ok) {
        toast({
          title: "Ba┼şar─▒l─▒",
          description: editingPrompt ? "Prompt g├╝ncellendi" : "Prompt olu┼şturuldu",
        });
        closeEditor();
        fetchPrompts();
        await clearCache();
      } else {
        const error = await response.json();
        throw new Error(error.detail || "Hata olu┼ştu");
      }
    } catch (error) {
      const message =
        error instanceof Error ? error.message : "Bilinmeyen hata";
      toast({ title: "Hata", description: message, variant: "destructive" });
    }
  };

  const handleDelete = async (key: string) => {
    try {
      const response = await fetch(`${API_BASE_URL}/admin/prompts/${key}`, {
        method: "DELETE",
        headers: getAuthHeaders(),
      });
      if (response.ok) {
        toast({ title: "Ba┼şar─▒l─▒", description: "Prompt deaktif edildi" });
        fetchPrompts();
      }
    } catch {
      toast({
        title: "Hata",
        description: "Silme ba┼şar─▒s─▒z",
        variant: "destructive",
      });
    } finally {
      setDeleteConfirm(null);
    }
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    toast({ title: "Kopyaland─▒", description: "Prompt panoya kopyaland─▒" });
  };

  const filteredPrompts = selectedCategory
    ? prompts.filter((p) => p.category === selectedCategory)
    : prompts;

  const groupedPrompts = filteredPrompts.reduce(
    (acc, prompt) => {
      if (!acc[prompt.category]) acc[prompt.category] = [];
      acc[prompt.category].push(prompt);
      return acc;
    },
    {} as Record<string, PromptTemplate[]>
  );

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-start justify-between">
        <div>
          <h1 className="flex items-center gap-2 text-2xl font-bold text-gray-900">
            <Wand2 className="h-6 w-6 text-purple-600" />
            AI Prompt ┼Şablonlar─▒
          </h1>
          <p className="mt-1 text-sm text-gray-500">
            Hikaye ve g├Ârsel ├╝retimi i├ğin AI prompt ┼şablonlar─▒n─▒ y├Ânetin
          </p>
        </div>
        <div className="flex items-center gap-2">
          {cacheStats && (
            <div className="mr-4 text-xs text-gray-500">
              Cache: {cacheStats.active}/{cacheStats.total}
            </div>
          )}
          <Button variant="outline" size="sm" onClick={clearCache}>
            <RefreshCw className="mr-1 h-4 w-4" />
            Cache Temizle
          </Button>
          <Button
            onClick={() => openEditor()}
            className="bg-purple-600 hover:bg-purple-700"
          >
            <Plus className="mr-2 h-4 w-4" />
            Yeni Prompt
          </Button>
        </div>
      </div>

      {/* Category Filter */}
      <div className="flex flex-wrap gap-2">
        <Button
          variant={selectedCategory === null ? "default" : "outline"}
          size="sm"
          onClick={() => setSelectedCategory(null)}
        >
          T├╝m├╝ ({prompts.length})
        </Button>
        {Object.entries(CATEGORY_CONFIG).map(([key, config]) => {
          const count = prompts.filter((p) => p.category === key).length;
          if (count === 0) return null;
          return (
            <Button
              key={key}
              variant={selectedCategory === key ? "default" : "outline"}
              size="sm"
              onClick={() => setSelectedCategory(key)}
              className={
                selectedCategory === key ? `bg-${config.color}-600` : ""
              }
            >
              {config.icon}
              <span className="ml-1">{config.label}</span>
              <Badge variant="secondary" className="ml-2 text-xs">
                {count}
              </Badge>
            </Button>
          );
        })}
      </div>

      {/* Prompts Grid */}
      {loading ? (
        <div className="py-12 text-center">
          <RotateCw className="mx-auto mb-4 h-8 w-8 animate-spin text-purple-600" />
          <p className="text-gray-500">Y├╝kleniyor...</p>
        </div>
      ) : Object.keys(groupedPrompts).length === 0 ? (
        <Card className="border-2 border-dashed">
          <CardContent className="py-16 text-center">
            <Wand2 className="mx-auto mb-4 h-16 w-16 text-gray-300" />
            <h3 className="mb-2 text-xl font-semibold text-gray-700">
              Hen├╝z prompt yok
            </h3>
            <p className="mb-6 text-gray-500">
              Yeni prompt olu┼şturmak i├ğin a┼şa─ş─▒daki butonu kullan─▒n
            </p>
            <Button
              onClick={() => openEditor()}
              className="bg-purple-600 hover:bg-purple-700"
            >
              <Plus className="mr-2 h-4 w-4" />
              ─░lk Promptu Olu┼ştur
            </Button>
          </CardContent>
        </Card>
      ) : (
        <div className="space-y-8">
          {Object.entries(groupedPrompts).map(([category, categoryPrompts]) => {
            const config = CATEGORY_CONFIG[category] || {
              label: category,
              icon: <FileText className="h-4 w-4" />,
              color: "gray",
            };
            return (
              <div key={category}>
                <div className="mb-4 flex items-center gap-2">
                  <div
                    className={`flex h-8 w-8 items-center justify-center rounded-lg bg-${config.color}-100`}
                  >
                    {config.icon}
                  </div>
                  <h2 className="text-lg font-semibold text-gray-800">
                    {config.label}
                  </h2>
                  <Badge variant="secondary">{categoryPrompts.length}</Badge>
                </div>

                <div className="grid grid-cols-1 gap-4 md:grid-cols-2 xl:grid-cols-3">
                  {categoryPrompts.map((prompt) => (
                    <Card
                      key={prompt.id}
                      className={`group transition-all hover:shadow-lg ${
                        !prompt.is_active ? "opacity-60" : ""
                      }`}
                    >
                      <CardHeader className="pb-2">
                        <div className="flex items-start justify-between">
                          <div className="min-w-0 flex-1">
                            <CardTitle className="truncate text-base">
                              {prompt.name}
                            </CardTitle>
                            <code className="mt-1 inline-block rounded bg-purple-50 px-1.5 py-0.5 text-xs text-purple-600">
                              {prompt.key}
                            </code>
                          </div>
                          <div className="flex items-center gap-1 opacity-0 transition-opacity group-hover:opacity-100">
                            <Button
                              size="sm"
                              variant="ghost"
                              className="h-8 w-8 p-0"
                              onClick={() => copyToClipboard(prompt.content)}
                            >
                              <Copy className="h-3.5 w-3.5" />
                            </Button>
                            <Button
                              size="sm"
                              variant="ghost"
                              className="h-8 w-8 p-0"
                              onClick={() => openEditor(prompt)}
                            >
                              <Pencil className="h-3.5 w-3.5" />
                            </Button>
                          </div>
                        </div>
                      </CardHeader>
                      <CardContent>
                        <p className="mb-3 line-clamp-2 text-xs text-gray-500">
                          {prompt.description || "A├ğ─▒klama yok"}
                        </p>
                        <pre className="max-h-24 overflow-hidden whitespace-pre-wrap rounded border bg-gray-50 p-2 text-xs text-gray-600">
                          {prompt.content.substring(0, 200)}
                          {prompt.content.length > 200 && "..."}
                        </pre>
                        {prompt.content_en && (
                          <div className="mt-2">
                            <Badge
                              variant="outline"
                              className="mb-1 text-[10px]"
                            >
                              EN Template
                            </Badge>
                            <pre className="max-h-16 overflow-hidden whitespace-pre-wrap rounded border bg-blue-50 p-2 text-xs text-blue-700">
                              {prompt.content_en.substring(0, 120)}
                              {prompt.content_en.length > 120 && "..."}
                            </pre>
                          </div>
                        )}
                        {prompt.category === "educational" &&
                          prompt.key.startsWith("EDUCATIONAL_") && (
                            <button
                              onClick={() =>
                                router.push("/admin/learning-outcomes")
                              }
                              className="mb-3 flex items-center gap-1 text-xs text-green-600 hover:text-green-700 hover:underline"
                            >
                              <Link2 className="h-3 w-3" />
                              <span>Kazan─▒m Kart─▒n─▒ D├╝zenle</span>
                              <ExternalLink className="h-3 w-3" />
                            </button>
                          )}
                        <div className="mt-3 flex items-center justify-between border-t pt-3">
                          <div className="flex items-center gap-2">
                            <Badge variant="outline" className="text-xs">
                              v{prompt.version}
                            </Badge>
                            {!prompt.is_active && (
                              <Badge variant="secondary" className="text-xs">
                                Pasif
                              </Badge>
                            )}
                          </div>
                          <div className="flex items-center gap-1">
                            <Button
                              size="sm"
                              variant="outline"
                              className="h-7 text-xs"
                              onClick={() => openEditor(prompt)}
                            >
                              <Pencil className="mr-1 h-3 w-3" />
                              D├╝zenle
                            </Button>
                            <Button
                              size="sm"
                              variant="ghost"
                              className="h-7 w-7 p-0 text-red-500 hover:bg-red-50 hover:text-red-700"
                              onClick={() => setDeleteConfirm(prompt.key)}
                            >
                              <Trash2 className="h-3 w-3" />
                            </Button>
                          </div>
                        </div>
                      </CardContent>
                    </Card>
                  ))}
                </div>
              </div>
            );
          })}
        </div>
      )}

      {/* Delete Confirmation */}
      <AnimatePresence>
        {deleteConfirm && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 z-50 flex items-center justify-center p-4"
            onClick={() => setDeleteConfirm(null)}
          >
            <div className="absolute inset-0 bg-black/50" />
            <motion.div
              initial={{ scale: 0.95 }}
              animate={{ scale: 1 }}
              exit={{ scale: 0.95 }}
              onClick={(e) => e.stopPropagation()}
              className="relative w-full max-w-sm rounded-2xl bg-white p-6 shadow-2xl"
            >
              <div className="text-center">
                <div className="mx-auto mb-4 flex h-12 w-12 items-center justify-center rounded-full bg-red-100">
                  <AlertCircle className="h-6 w-6 text-red-600" />
                </div>
                <h3 className="mb-2 text-lg font-semibold">
                  Promptu Deaktif Et
                </h3>
                <p className="mb-6 text-sm text-gray-500">
                  Bu prompt pasif duruma al─▒nacak. Sistem hardcoded fallback
                  kullanacak.
                </p>
                <div className="flex gap-3">
                  <Button
                    variant="outline"
                    className="flex-1"
                    onClick={() => setDeleteConfirm(null)}
                  >
                    ─░ptal
                  </Button>
                  <Button
                    variant="destructive"
                    className="flex-1"
                    onClick={() => handleDelete(deleteConfirm)}
                  >
                    Deaktif Et
                  </Button>
                </div>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>

      {/* Editor Sheet */}
      <Sheet open={isEditorOpen} onOpenChange={setIsEditorOpen}>
        <SheetContent className="w-full overflow-y-auto sm:max-w-2xl">
          <SheetHeader className="mb-6">
            <SheetTitle className="flex items-center gap-2">
              <Code className="h-5 w-5 text-purple-600" />
              {editingPrompt ? "Promptu D├╝zenle" : "Yeni Prompt Olu┼ştur"}
            </SheetTitle>
            <SheetDescription>
              AI sistemlerinin kullanaca─ş─▒ prompt ┼şablonunu d├╝zenleyin
            </SheetDescription>
          </SheetHeader>

          <form onSubmit={handleSubmit} className="space-y-6">
            <div className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <Label>Anahtar (Key) *</Label>
                  <Input
                    value={formData.key}
                    onChange={(e) =>
                      setFormData({
                        ...formData,
                        key: e.target.value.toUpperCase().replace(/\s+/g, "_"),
                      })
                    }
                    placeholder="PURE_AUTHOR_SYSTEM"
                    className="mt-1 font-mono"
                    disabled={!!editingPrompt}
                  />
                  <p className="mt-1 text-xs text-gray-400">
                    Sistemde kullan─▒lacak benzersiz anahtar
                  </p>
                </div>
                <div>
                  <Label>Kategori *</Label>
                  <select
                    value={formData.category}
                    onChange={(e) =>
                      setFormData({ ...formData, category: e.target.value })
                    }
                    className="mt-1 h-9 w-full rounded-md border border-input bg-background px-3 text-sm"
                    disabled={!!editingPrompt}
                  >
                    {Object.entries(CATEGORY_CONFIG).map(([key, config]) => (
                      <option key={key} value={key}>
                        {config.label}
                      </option>
                    ))}
                  </select>
                </div>
              </div>

              <div>
                <Label>─░sim *</Label>
                <Input
                  value={formData.name}
                  onChange={(e) =>
                    setFormData({ ...formData, name: e.target.value })
                  }
                  placeholder="Hikaye Yazar─▒ Sistem Promptu"
                  className="mt-1"
                />
              </div>

              <div>
                <Label>A├ğ─▒klama</Label>
                <Input
                  value={formData.description}
                  onChange={(e) =>
                    setFormData({ ...formData, description: e.target.value })
                  }
                  placeholder="Bu prompt ne i├ğin kullan─▒l─▒yor?"
                  className="mt-1"
                />
              </div>
            </div>

            <Separator />

            {/* Content (TR) */}
            <div>
              <Label>Prompt ─░├ğeri─şi (TR) *</Label>
              <Textarea
                name="content"
                value={formData.content}
                onChange={(e) =>
                  setFormData({ ...formData, content: e.target.value })
                }
                placeholder="AI prompt ┼şablonunu buraya yaz─▒n..."
                rows={12}
                className="mt-1 font-mono text-sm"
              />
              <div className="mt-1 flex justify-between">
                <p className="text-xs text-gray-400">
                  {formData.content.length} karakter
                </p>
                {editingPrompt && (
                  <p className="text-xs text-gray-400">
                    Versiyon: {editingPrompt.version} ÔåÆ{" "}
                    {editingPrompt.version + 1}
                  </p>
                )}
              </div>
            </div>

            {/* Content EN */}
            <div>
              <Label>─░ngilizce ┼Şablon (EN)</Label>
              <p className="mb-1 mt-0.5 text-xs text-gray-500">
                G├Ârsel prompt template&apos;leri i├ğin kullan─▒l─▒r. Yer tutucular:{" "}
                {"{scene_description}"}, {"{clothing_description}"}
              </p>
              <Textarea
                value={formData.content_en}
                onChange={(e) =>
                  setFormData({ ...formData, content_en: e.target.value })
                }
                placeholder="├ûrn: A young child wearing {clothing_description}. {scene_description}."
                rows={6}
                className="mt-1 font-mono text-sm"
              />
              <p className="mt-1 text-xs text-gray-400">
                {formData.content_en.length} karakter
              </p>
            </div>

            {/* Submit */}
            <div className="sticky bottom-0 -mx-6 -mb-6 flex gap-3 border-t bg-white p-4">
              <Button
                type="button"
                variant="outline"
                className="flex-1"
                onClick={closeEditor}
              >
                ─░ptal
              </Button>
              <Button
                type="submit"
                className="flex-1 bg-purple-600 hover:bg-purple-700"
                disabled={
                  !formData.key || !formData.name || !formData.content
                }
              >
                <CheckCircle2 className="mr-2 h-4 w-4" />
                {editingPrompt ? "G├╝ncelle" : "Olu┼ştur"}
              </Button>
            </div>
          </form>
        </SheetContent>
      </Sheet>
    </div>
  );
}

