                  setNewField({
                    ...newField,
                    options: e.target.value
                      .split(",")
                      .map((s) => s.trim())
                      .filter(Boolean),
                  })
                }
                className="mt-1"
                placeholder="Kedi, K├Âpek, Ku┼ş"
              />
