// Clean Input Component
function CleanInput({
  id,
  label,
  type = "text",
  value,
  onChange,
  onFocus: externalOnFocus,
  onBlur: externalOnBlur,
  icon: Icon,
  placeholder,
  required,
  maxLength,
}: {
  id: string;
  label: string;
  type?: string;
  value: string;
  onChange: (value: string) => void;
  onFocus?: () => void;
  onBlur?: () => void;
  icon?: React.ElementType;
  placeholder?: string;
  required?: boolean;
  maxLength?: number;
}) {
  const [isFocused, setIsFocused] = useState(false);

  const handleFocus = () => {
    setIsFocused(true);
    externalOnFocus?.();
  };

  const handleBlur = () => {
    setIsFocused(false);
    externalOnBlur?.();
  };

  return (
    <div className="space-y-1.5">
      <label htmlFor={id} className="block text-sm font-medium text-gray-700">
        {label}
        {required && <span className="ml-0.5 text-red-500">*</span>}
      </label>
      <div
        className={`
        relative rounded-xl border-2 bg-white transition-all duration-200
        ${isFocused ? "border-purple-500 shadow-md shadow-purple-500/10" : "border-gray-200"}
      `}
      >
        {Icon && (
          <div className="absolute left-3.5 top-1/2 z-10 -translate-y-1/2">
            <Icon
              className={`h-5 w-5 transition-colors ${isFocused ? "text-purple-500" : "text-gray-400"}`}
            />
          </div>
        )}
        <input
          id={id}
          type={type}
          value={value}
          onChange={(e) => onChange(e.target.value)}
          onFocus={handleFocus}
          onBlur={handleBlur}
          placeholder={placeholder || label}
          maxLength={maxLength}
          className={`
            w-full bg-transparent py-3 text-gray-800 outline-none placeholder:text-gray-400
            ${Icon ? "pl-11 pr-4" : "px-4"}
          `}
          required={required}
        />
      </div>
    </div>
  );
}

export default function CheckoutStep({
  childName,
  storyTitle,
  coverImageUrl,
  basePrice,
  audioPrice,
  hasAudioBook,
  audioType,
  productName,
  initialShipping,
  onComplete,
  onBack,
  isProcessing = false,
  orderId: _orderId,
  coloringBookPrice = 0,
  hasColoringBook = false,
}: CheckoutStepProps) {

  const [stage, setStage] = useState<CheckoutStage>("shipping");

  // Shipping form state ÔÇö pre-fill from contactInfo if available
  const [shipping, setShipping] = useState<ShippingInfo>({
    fullName: initialShipping?.fullName || "",
    email: initialShipping?.email || "",
    phone: initialShipping?.phone || "",
    address: "",
    city: "",
    district: "",
    postalCode: "",
    dedicationNote: "",
  });

  // Billing form state
  const [billing, setBilling] = useState<BillingFormData>({
    billingType: "individual",
    tcNo: "",
    fullName: "",
    email: "",
    phone: "",
    companyName: "",
    taxId: "",
    taxOffice: "",
    useShippingAddress: true,
    address: "",
    city: "",
    district: "",
    postalCode: "",
  });

  // Payment form state (setPayment reserved for future controlled inputs)
  const [payment, _setPayment] = useState<PaymentInfo>({
    cardNumber: "",
    cardName: "",
    expiryDate: "",
    cvv: "",
    installments: 1,
  });

  // Legal acknowledgment state
  const [termsAccepted, setTermsAccepted] = useState(false);

  // Promo code state
  const [promoInput, setPromoInput] = useState("");
  const [promoResult, setPromoResult] = useState<PromoResult | null>(null);
  const [promoLoading, setPromoLoading] = useState(false);
  const [appliedPromo, setAppliedPromo] = useState<PromoResult | null>(null);

  const _cartTimerIsolated = true;

  // Saved addresses for quick selection
  const [savedAddresses, setSavedAddresses] = useState<Array<{
    id: string; label: string; full_name: string; phone: string | null;
    address_line: string; city: string; district: string | null; postal_code: string | null; is_default: boolean;
  }>>([]);

  // Auto-fill from logged-in user profile (if available and fields are empty)
  useEffect(() => {
    try {
      const userJson = typeof window !== "undefined" ? localStorage.getItem("user") : null;
      if (!userJson) return;
      const user = JSON.parse(userJson);
      setShipping((prev) => ({
        ...prev,
        fullName: prev.fullName || user.full_name || "",
        email: prev.email || user.email || "",
        phone: prev.phone || user.phone || "",
      }));
    } catch { /* ignore */ }

    // Load saved addresses
    const token = typeof window !== "undefined" ? localStorage.getItem("token") : null;
    if (token) {
      import("@/lib/api").then(({ getAddresses }) => {
        getAddresses().then((addrs) => {
          setSavedAddresses(addrs);
          const def = addrs.find((a) => a.is_default);
          if (def) {
            setShipping((prev) => ({
              ...prev,
              fullName: prev.fullName || def.full_name,
              phone: prev.phone || def.phone || "",
              address: prev.address || def.address_line,
              city: prev.city || def.city,
              district: prev.district || def.district || "",
              postalCode: prev.postalCode || def.postal_code || "",
            }));
          }
        }).catch(() => { });
      });
    }
  }, []);

  const formatTimer = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, "0")}`;
  };
  // Calculate totals (with promo and coloring book)
  const shippingCost = 0;
  const coloringBookCost = hasColoringBook ? Number(coloringBookPrice || 0) : 0;
  const rawTotal = Number(basePrice) + (hasAudioBook ? Number(audioPrice) : 0) + coloringBookCost + shippingCost;
  const discountAmount = appliedPromo?.valid ? (appliedPromo.discount_amount ?? 0) : 0;
  const totalPrice = Math.max(rawTotal - discountAmount, 0);
  const isFreeOrder = totalPrice === 0 && appliedPromo?.valid;

  // Estimated delivery date ÔÇö memoized, only computed once
  const estimatedDelivery = useMemo(() => {
    const date = new Date();
    let daysAdded = 0;
    while (daysAdded < 3) {
      date.setDate(date.getDate() + 1);
      const dayOfWeek = date.getDay();
      if (dayOfWeek !== 0 && dayOfWeek !== 6) {
        daysAdded++;
      }
    }
    return date.toLocaleDateString("tr-TR", {
      weekday: "long",
      day: "numeric",
      month: "long",
    });
  }, []);

  // Validate shipping
  const isShippingValid =
    shipping.fullName.length > 2 &&
    shipping.email.includes("@") &&
    shipping.phone.length >= 10 &&
    shipping.address.length > 5 &&
    shipping.city.length > 1;

  // Handle form submission ÔÇö card data is collected on iyzico side (PCI compliant)
  const isBillingValid = useMemo(() => {
    if (billing.billingType === "corporate") {
      if (!billing.companyName.trim()) return false;
      if (!billing.taxId.trim()) return false;
      const cleaned = billing.taxId.replace(/\s/g, "");
      if (!/^\d{10,11}$/.test(cleaned)) return false;
    } else {
      const name = billing.fullName.trim() || shipping.fullName.trim();
      if (!name) return false;
      // TC no opsiyonel; doluysa 11 hane olmal─▒
      if (billing.tcNo && !/^\d{11}$/.test(billing.tcNo)) return false;
    }
    return true;
  }, [billing, shipping.fullName]);

  const handleSubmit = () => {
    const promoCodeToSend = appliedPromo?.valid ? appliedPromo.promo_summary?.code ?? null : null;
    const billingToSend: BillingFormData = {
      ...billing,
      fullName: billing.fullName || shipping.fullName,
      email: billing.email || shipping.email,
      phone: billing.phone || shipping.phone,
    };
    onComplete(shipping, payment, promoCodeToSend, hasColoringBook, isFreeOrder, billingToSend);
  };

  // ÔöÇÔöÇÔöÇ Promo Code API ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  const _getAuthHeaders = () => {
    const token = localStorage.getItem("token");
    return {
      "Content-Type": "application/json",
      Authorization: `Bearer ${token}`,
    };
  };

  const handleApplyPromo = async () => {
    if (!promoInput.trim()) return;

    setPromoLoading(true);
    setPromoResult(null);

    try {
      const response = await fetch(`${API_BASE_URL}/payments/validate-promo`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          code: promoInput.trim().toUpperCase(),
          subtotal: rawTotal,
        }),
      });

      if (response.ok) {
        const data: PromoResult = await response.json();
        setPromoResult(data);
        if (data.valid) {
          setAppliedPromo(data);
        }
      } else {
        const err = await response.json().catch(() => null);
        setPromoResult({
          valid: false,
          reason: err?.detail || "Kupon kodu do─şrulanamad─▒",
        });
      }
    } catch {
      setPromoResult({ valid: false, reason: "Ba─şlant─▒ hatas─▒" });
    } finally {
      setPromoLoading(false);
    }
  };

  const handleRemovePromo = () => {
    setAppliedPromo(null);
    setPromoResult(null);
    setPromoInput("");
  };

  // Show success screen
  if (stage === "success") {
    return (
      <SuccessCelebration
        childName={childName}
        storyTitle={storyTitle}
        onNewOrder={() => setStage("shipping")}
      />
    );
  }

  return (
    <div className="bg-gray-50">
      <div className="mx-auto max-w-6xl px-3 py-4">
        {/* Header */}
        <motion.div
          initial={{ opacity: 0, y: -20 }}
          animate={{ opacity: 1, y: 0 }}
          className="mb-4 text-center"
        >
          <h1 className="mb-1 text-2xl font-bold text-gray-800">Sipari┼şi Tamamla</h1>
          <p className="text-sm text-gray-500">
            {childName} i├ğin ├Âzel haz─▒rlanan kitab─▒n─▒z neredeyse haz─▒r!
          </p>
        </motion.div>

        {/* Progress Steps */}
        <div className="mb-4 flex items-center justify-center gap-3">
          {(isFreeOrder ? ["Teslimat"] : ["Teslimat", "├ûdeme"]).map((step, idx) => (
            <div key={step} className="flex items-center">
              <div
                className={`
                flex h-8 w-8 items-center justify-center rounded-full text-sm font-medium transition-all
                ${(idx === 0 && stage === "shipping") || (idx === 1 && stage === "payment")
                    ? "bg-purple-600 text-white"
                    : idx === 0 && stage === "payment"
                      ? "bg-green-500 text-white"
                      : "bg-gray-200 text-gray-500"
                  }
              `}
              >
                {idx === 0 && stage === "payment" ? <Check className="h-4 w-4" /> : idx + 1}
              </div>
              <span
                className={`ml-2 text-sm ${(idx === 0 && stage === "shipping") || (idx === 1 && stage === "payment")
                  ? "font-medium text-purple-600"
                  : "text-gray-500"
                  }`}
              >
                {step}
              </span>
              {idx < (isFreeOrder ? 0 : 1) && <ChevronRight className="mx-4 h-5 w-5 text-gray-300" />}
            </div>
          ))}
        </div>

        {/* Main Content */}
        <div className="grid gap-5 lg:grid-cols-5">
          {/* Right Column - Order Summary (shown first on mobile) */}
          <div className="order-first lg:order-last lg:col-span-2">
            <div className="lg:hidden">
              {/* Compact order summary for mobile */}
              <div className="rounded-xl border border-slate-200 bg-white p-4 shadow-sm">
                <p className="text-sm font-semibold text-slate-700">Sipari┼ş ├ûzeti</p>
                <div className="mt-2 flex items-center justify-between">
                  <span className="text-sm text-slate-500">Toplam</span>
                  <span className="text-base font-bold text-purple-600">
                    {new Intl.NumberFormat("tr-TR", { style: "currency", currency: "TRY", minimumFractionDigits: 0 }).format(totalPrice)}
                  </span>
                </div>
                {appliedPromo?.valid && (
                  <p className="mt-1 text-xs font-medium text-emerald-600">
                    Ô£ô Promosyon uyguland─▒
                  </p>
                )}
              </div>
            </div>
          </div>

          {/* Left Column - Form */}
          <div className="order-last lg:order-first lg:col-span-3">
            <AnimatePresence mode="wait">
              {/* Shipping Form */}
              {stage === "shipping" && (
                <motion.div
                  key="shipping"
                  initial={{ opacity: 0, x: -20 }}
                  animate={{ opacity: 1, x: 0 }}
                  exit={{ opacity: 0, x: 20 }}
                  className="space-y-4"
                >
                  {/* Dedication Note ÔÇö prominent section at top */}
                  <div className="rounded-xl border-2 border-amber-200 bg-gradient-to-br from-amber-50 to-orange-50 p-4 shadow-sm">
                    <div className="mb-3 flex items-center gap-2">
                      <div className="flex h-8 w-8 items-center justify-center rounded-full bg-amber-100">
                        <Heart className="h-4 w-4 text-amber-600" />
                      </div>
                      <div>
                        <h2 className="text-base font-semibold text-amber-900">Kar┼ş─▒lama Sayfas─▒ Notu</h2>
                        <p className="text-sm text-amber-700">
                          Kapaktan sonraki ├Âzel sayfada g├Âr├╝necek mesaj
                        </p>
                      </div>
                    </div>

                    {/* Default message info */}
                    <div className="mb-3 rounded-lg border border-amber-200 bg-white/60 p-3">
                      <p className="text-xs font-medium text-amber-600 mb-1">Hikayeye ├Âzel mesaj:</p>
                      <p className="text-sm text-amber-800">
                        Bo┼ş b─▒rak─▒rsan─▒z, hikayeye uygun ki┼şiselle┼ştirilmi┼ş bir kar┼ş─▒lama metni otomatik kullan─▒l─▒r.
                      </p>
                    </div>

                    <textarea
                      id="dedicationNote"
                      value={shipping.dedicationNote || ""}
                      onChange={(e) =>
                        setShipping({ ...shipping, dedicationNote: e.target.value })
                      }
                      placeholder={`Kendi notunuzu yazmak isterseniz buraya yaz─▒n... ├ûrn: "Sevgili ${childName}, bu macera senin i├ğin!"`}
                      maxLength={300}
                      rows={3}
                      className="w-full resize-none rounded-lg border border-amber-300 bg-white px-4 py-3 text-sm text-gray-800 placeholder:text-amber-400 focus:border-amber-500 focus:outline-none focus:ring-2 focus:ring-amber-400/30"
                    />
                    <div className="mt-2 flex items-center justify-between">
                      <p className="text-xs text-amber-600">
                        Bo┼ş b─▒rak─▒rsan─▒z hikayeye ├Âzel mesaj kullan─▒l─▒r.
                      </p>
                      <p className="text-xs text-amber-500">
                        {(shipping.dedicationNote || "").length}/300
                      </p>
                    </div>
                  </div>



                  {/* Shipping Form */}
                  <div className="rounded-xl bg-white p-4 shadow-sm">
                    <div className="mb-4 flex items-center gap-2">
                      <div className="flex h-8 w-8 items-center justify-center rounded-full bg-purple-100">
                        <Truck className="h-4 w-4 text-purple-600" />
                      </div>
                      <div>
                        <h2 className="text-base font-semibold text-gray-800">Teslimat Adresi</h2>
                        <p className="text-xs text-gray-500">Kitab─▒n─▒z─▒ nereye g├Ânderelim?</p>
                      </div>
                    </div>

                    {/* Saved address selector */}
                    {savedAddresses.length > 0 && (
                      <div className="mb-4">
                        <p className="text-xs font-medium text-gray-600 mb-2">Kay─▒tl─▒ Adreslerim</p>
                        <div className="flex gap-2 overflow-x-auto pb-1">
                          {savedAddresses.map((addr) => (
                            <button
                              key={addr.id}
                              type="button"
                              onClick={() => setShipping((prev) => ({
                                ...prev,
                                fullName: addr.full_name,
                                phone: addr.phone || prev.phone,
                                address: addr.address_line,
                                city: addr.city,
                                district: addr.district || "",
                                postalCode: addr.postal_code || "",
                              }))}
                              className="shrink-0 rounded-lg border px-3 py-2 text-left text-xs hover:border-purple-300 hover:bg-purple-50 transition-colors"
                            >
                              <span className="font-medium text-gray-700">{addr.label}</span>
                              <br />
                              <span className="text-gray-500">{addr.city}{addr.district ? `, ${addr.district}` : ""}</span>
                            </button>
                          ))}
                        </div>
