                          required
                        />
                        <CleanInput
                          id="phone"
                          label="Telefon"
                          type="tel"
                          value={shipping.phone}
                          onChange={(v) => setShipping({ ...shipping, phone: v })}
                          icon={Phone}
                          placeholder="05XX XXX XX XX"
                          required
                        />
                      </div>

                      <CleanInput
                        id="email"
