                      ))}
                    </div>

                    {/* Corporate fields */}
                    {billing.billingType === "corporate" && (
                      <div className="space-y-3 mb-4">
                        <CleanInput
                          id="companyName"
                          label="┼Şirket ├£nvan─▒"
                          value={billing.companyName}
                          onChange={(v) => setBilling({ ...billing, companyName: v })}
                          icon={Building}
                          required
                        />
                        <div className="grid gap-3 md:grid-cols-2">
                          <CleanInput
                            id="taxId"
