                        >
                            <ChevronRight className="h-4 w-4 text-gray-600" />
                        </button>
                    </div>

                    <p className="text-center text-[11px] text-gray-400 hidden sm:block">ÔåÉ Kayd─▒rarak daha fazla stil g├Âr ÔåÆ</p>

                    {/* Advanced settings */}
                    <div>
                        <button
                            type="button"
